-- ============================================================
-- WASSCEPrep — Full Question Bank
-- 50 Paper 1 MCQ questions per subject (400 total)
-- Plus Paper 2 essay/theory questions per subject
-- Run after 001 and 002 migrations
-- ============================================================

-- Add paper_number column to questions if not present
ALTER TABLE questions ADD COLUMN IF NOT EXISTS paper_number INT DEFAULT 1;
ALTER TABLE questions ADD COLUMN IF NOT EXISTS question_type TEXT DEFAULT 'mcq' CHECK (question_type IN ('mcq','essay','structured','practical'));
ALTER TABLE questions ADD COLUMN IF NOT EXISTS marks INT DEFAULT 1;
ALTER TABLE questions ADD COLUMN IF NOT EXISTS mark_scheme TEXT;
ALTER TABLE questions ADD COLUMN IF NOT EXISTS section TEXT;

-- Essay answers table for Paper 2 & 3 submissions
CREATE TABLE IF NOT EXISTS essay_answers (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id         UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  session_id      UUID REFERENCES quiz_sessions(id),
  question_id     UUID REFERENCES questions(id),
  subject         TEXT NOT NULL,
  paper_number    INT NOT NULL,
  answer_text     TEXT NOT NULL,
  marks_awarded   INT,
  max_marks       INT,
  percentage      FLOAT,
  justification   TEXT,
  strengths       JSONB,
  missing_points  JSONB,
  feedback        TEXT,
  ai_status       TEXT DEFAULT 'pending' CHECK (ai_status IN ('pending','marked','failed','manual_review')),
  created_at      TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_essay_answers_user ON essay_answers(user_id, created_at DESC);

ALTER TABLE essay_answers ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Users can view own essay answers" ON essay_answers FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Users can insert own essay answers" ON essay_answers FOR INSERT WITH CHECK (auth.uid() = user_id);

