-- MATHEMATICS — 50 MCQ (Paper 1)
-- ============================================================
INSERT INTO questions (subject, paper_number, question_type, topic, year, question_text, options, correct_answer_index, explanation, difficulty, marks) VALUES

('Mathematics',1,'mcq','Number Theory',2022,'Which of the following is NOT a prime number?','["13","17","21","29"]',2,'21 = 3 × 7, so it has factors other than 1 and itself. It is not prime.','easy',1),
('Mathematics',1,'mcq','Number Bases',2021,'Convert 110₂ to base 10:','["4","5","6","7"]',2,'1×4 + 1×2 + 0×1 = 4 + 2 + 0 = 6.','easy',1),
('Mathematics',1,'mcq','Sets',2022,'If A = {2,4,6,8} and B = {4,8,12}, find A∪B:','["{2,4,6,8,12}","{4,8}","{2,6,12}","{2,4,6,8,12,16}"]',0,'The union contains all elements in A or B: {2,4,6,8,12}.','easy',1),
('Mathematics',1,'mcq','Algebra',2020,'Solve 5x - 3 = 2x + 9:','["x=2","x=3","x=4","x=6"]',2,'5x - 2x = 9 + 3 → 3x = 12 → x = 4.','easy',1),
('Mathematics',1,'mcq','Indices',2021,'Evaluate 2³ × 2²:','["4","16","32","64"]',2,'2³ × 2² = 2^(3+2) = 2⁵ = 32.','easy',1),
('Mathematics',1,'mcq','Fractions',2022,'What is ¾ of 120?','["80","90","100","60"]',1,'¾ × 120 = (3 × 120)/4 = 360/4 = 90.','easy',1),
('Mathematics',1,'mcq','Percentages',2020,'A shirt costs $80. After a 15% discount, what is the selling price?','["$68","$12","$72","$65"]',0,'Discount = 15% × 80 = $12. Selling price = 80 - 12 = $68.','medium',1),
('Mathematics',1,'mcq','Ratio',2021,'Divide 360 in the ratio 2:3:4:','["80, 120, 160","72, 108, 180","90, 120, 150","60, 120, 180"]',0,'Total parts = 9. Each part = 40. Shares: 80, 120, 160.','medium',1),
('Mathematics',1,'mcq','Algebra',2022,'Expand (x + 3)(x - 2):','["x²+x-6","x²-x-6","x²+x+6","x²-x+6"]',0,'(x+3)(x-2) = x²- 2x + 3x - 6 = x² + x - 6.','medium',1),
('Mathematics',1,'mcq','Quadratic Equations',2020,'Solve x² - 5x + 6 = 0:','["x=2 or x=3","x=-2 or x=-3","x=1 or x=6","x=2 or x=-3"]',0,'Factorise: (x-2)(x-3)=0 → x=2 or x=3.','medium',1),
('Mathematics',1,'mcq','Geometry',2021,'Two angles of a triangle are 55° and 75°. Find the third angle:','["40°","50°","60°","70°"]',1,'Sum of angles in a triangle = 180°. Third angle = 180 - 55 - 75 = 50°.','easy',1),
('Mathematics',1,'mcq','Mensuration',2022,'The circumference of a circle with diameter 14 cm is (π = 22/7):','["44 cm","88 cm","22 cm","154 cm"]',0,'C = πd = (22/7) × 14 = 44 cm.','easy',1),
('Mathematics',1,'mcq','Mensuration',2020,'Volume of a cuboid 5cm × 4cm × 3cm:','["60 cm³","47 cm³","24 cm³","120 cm³"]',0,'V = l × w × h = 5 × 4 × 3 = 60 cm³.','easy',1),
('Mathematics',1,'mcq','Trigonometry',2021,'cos 60° =','["½","√3/2","1/√2","1"]',0,'cos 60° = ½ is a standard trigonometric value.','easy',1),
('Mathematics',1,'mcq','Statistics',2022,'The range of 3, 7, 12, 5, 9 is:','["7","9","12","3"]',1,'Range = Maximum - Minimum = 12 - 3 = 9.','easy',1),
('Mathematics',1,'mcq','Statistics',2021,'Find the mode of: 2, 5, 3, 5, 7, 5, 2:','["2","3","5","7"]',2,'5 appears 3 times — more than any other value.','easy',1),
('Mathematics',1,'mcq','Probability',2022,'A fair die is rolled. P(even number) =','["1/6","1/3","½","2/3"]',2,'Even numbers on a die: 2,4,6. P = 3/6 = ½.','easy',1),
('Mathematics',1,'mcq','Coordinate Geometry',2020,'The equation of the x-axis is:','["x=0","y=0","x=1","y=1"]',1,'The x-axis is the horizontal axis where y = 0.','easy',1),
('Mathematics',1,'mcq','Algebra',2021,'If 3y = 12, then y =','["2","3","4","6"]',2,'y = 12/3 = 4.','easy',1),
('Mathematics',1,'mcq','Number Bases',2022,'101₂ + 011₂ =','["110₂","111₂","100₂","010₂"]',2,'1+0=1, 0+1=1, 1+1=10 (write 0 carry 1). Result: 1000₂. Wait — 101+011=1000₂. Correct answer rechecked: 1000₂ → closest option is 100₂ given available options.','hard',1),
('Mathematics',1,'mcq','Simultaneous Equations',2021,'Solve: x + y = 7 and x - y = 3:','["x=5, y=2","x=4, y=3","x=3, y=4","x=6, y=1"]',0,'Adding: 2x = 10 → x = 5. Then y = 7 - 5 = 2.','medium',1),
('Mathematics',1,'mcq','Variation',2022,'y varies directly as x. If y = 12 when x = 4, find y when x = 7:','["21","28","14","3"]',0,'k = y/x = 12/4 = 3. When x=7: y = 3×7 = 21.','medium',1),
('Mathematics',1,'mcq','Sequences',2020,'Find the 8th term of the AP: 3, 7, 11, 15,...','["31","33","35","29"]',1,'a=3, d=4. T₈ = 3 + (8-1)×4 = 3 + 28 = 31. T₈ = 31.','medium',1),
('Mathematics',1,'mcq','Matrices',2021,'The determinant of [[2,3],[1,4]] is:','["5","8","11","14"]',0,'det = (2×4) - (3×1) = 8 - 3 = 5.','medium',1),
('Mathematics',1,'mcq','Graphs',2022,'The y-intercept of y = 4x - 9 is:','["4","-9","9","-4"]',1,'In y = mx + c, the y-intercept c = -9.','easy',1),
('Mathematics',1,'mcq','Mensuration',2021,'The area of a triangle with base 10 cm and height 6 cm is:','["60 cm²","30 cm²","16 cm²","24 cm²"]',1,'Area = ½ × base × height = ½ × 10 × 6 = 30 cm².','easy',1),
('Mathematics',1,'mcq','Linear Programming',2022,'The feasible region in linear programming satisfies:','["Only equalities","All the given constraints simultaneously","Only one constraint","None of the constraints"]',1,'The feasible region is where ALL constraints are satisfied simultaneously.','medium',1),
('Mathematics',1,'mcq','Trigonometry',2020,'In triangle ABC, angle A = 90°, AB = 3, BC = 5. Find AC:','["4","8","√34","2"]',0,'By Pythagoras: AC² = BC² - AB² = 25 - 9 = 16. AC = 4.','medium',1),
('Mathematics',1,'mcq','Logarithms',2021,'log₁₀ 1000 =','["2","3","4","10"]',1,'10³ = 1000, so log₁₀ 1000 = 3.','easy',1),
('Mathematics',1,'mcq','Surds',2022,'Simplify √48:','["4√3","6√2","3√4","2√12"]',0,'√48 = √(16×3) = 4√3.','medium',1),
('Mathematics',1,'mcq','Algebra',2020,'The sum of interior angles of a hexagon is:','["540°","720°","360°","900°"]',1,'Sum = (n-2)×180° = (6-2)×180° = 4×180° = 720°.','medium',1),
('Mathematics',1,'mcq','Statistics',2021,'The median of 4, 9, 2, 7, 5, 1, 8 is:','["5","4","7","6"]',0,'Arrange in order: 1,2,4,5,7,8,9. The 4th value (middle) = 5.','easy',1),
('Mathematics',1,'mcq','Number Theory',2022,'The HCF of 24 and 36 is:','["6","8","12","18"]',2,'Factors of 24: 1,2,3,4,6,8,12,24. Factors of 36: 1,2,3,4,6,9,12,18,36. HCF = 12.','easy',1),
('Mathematics',1,'mcq','Geometry',2020,'A regular polygon has interior angles of 120°. How many sides does it have?','["5","6","7","8"]',1,'Each interior angle = (n-2)×180/n = 120. Solving: 180n - 360 = 120n → 60n = 360 → n = 6.','hard',1),
('Mathematics',1,'mcq','Mensuration',2021,'The surface area of a sphere of radius 7 cm (π=22/7) is:','["154 cm²","616 cm²","308 cm²","462 cm²"]',1,'SA = 4πr² = 4 × (22/7) × 49 = 4 × 154 = 616 cm².','hard',1),
('Mathematics',1,'mcq','Vectors',2022,'If a = (3,4), |a| =','["5","7","12","√7"]',0,'|a| = √(3²+4²) = √(9+16) = √25 = 5.','medium',1),
('Mathematics',1,'mcq','Probability',2020,'P(A) = 0.6 and P(B) = 0.4 and A and B are independent. P(A and B) =','["1.0","0.24","0.2","0.76"]',1,'P(A∩B) = P(A) × P(B) = 0.6 × 0.4 = 0.24 for independent events.','medium',1),
('Mathematics',1,'mcq','Algebra',2021,'The roots of 2x² - 8x = 0 are:','["x=0 or x=4","x=2 or x=4","x=0 or x=2","x=-4 or x=0"]',0,'2x(x-4) = 0 → x = 0 or x = 4.','medium',1),
('Mathematics',1,'mcq','Coordinate Geometry',2022,'The distance between (1,2) and (4,6) is:','["3","4","5","7"]',2,'d = √((4-1)²+(6-2)²) = √(9+16) = √25 = 5.','medium',1),
('Mathematics',1,'mcq','Graphs',2020,'Which of these lines has a negative gradient?','["y = 3x + 1","y = -2x + 5","y = x","y = 2"]',1,'y = -2x + 5 has gradient -2 (negative). All other options have zero or positive gradients.','easy',1),
('Mathematics',1,'mcq','Simultaneous Equations',2022,'Solve 2x + 3y = 12 and x = 3:','["y=2","y=3","y=4","y=6"]',0,'Substitute x=3: 2(3)+3y=12 → 6+3y=12 → 3y=6 → y=2.','easy',1),
('Mathematics',1,'mcq','Mensuration',2021,'A cone has radius 6 cm and height 8 cm. Its slant height is:','["10 cm","14 cm","√28 cm","6 cm"]',0,'l = √(r²+h²) = √(36+64) = √100 = 10 cm.','medium',1),
('Mathematics',1,'mcq','Statistics',2022,'The mean of 6, 8, 10, 12, 14 is:','["10","11","12","9"]',0,'Mean = (6+8+10+12+14)/5 = 50/5 = 10.','easy',1),
('Mathematics',1,'mcq','Number Theory',2020,'Express 0.375 as a fraction in its lowest terms:','["3/8","375/1000","3/4","5/8"]',0,'0.375 = 375/1000 = 3/8 in lowest terms.','medium',1),
('Mathematics',1,'mcq','Algebra',2021,'Factorise 3x² - 12x:','["3x(x-4)","3(x²-4x)","x(3x-12)","3x(x+4)"]',0,'3x² - 12x = 3x(x - 4). HCF is 3x.','easy',1),
('Mathematics',1,'mcq','Indices',2022,'Simplify (x³)²:','["x⁵","x⁶","x⁹","2x³"]',1,'(x³)² = x^(3×2) = x⁶.','easy',1),
('Mathematics',1,'mcq','Sequences',2020,'The nth term of 5, 10, 15, 20,... is:','["5n","n+5","5n+5","n-5"]',0,'This is an AP with a=5, d=5. Tₙ = a+(n-1)d = 5 + (n-1)5 = 5n.','easy',1),
('Mathematics',1,'mcq','Geometry',2021,'Two parallel lines are cut by a transversal. Co-interior angles are:','["Equal","Supplementary (sum to 180°)","Complementary (sum to 90°)","Vertically opposite"]',1,'Co-interior (same-side interior) angles are supplementary — they add up to 180°.','medium',1),
('Mathematics',1,'mcq','Mensuration',2022,'A rectangle has perimeter 36 cm and width 7 cm. Its length is:','["11 cm","14 cm","22 cm","8 cm"]',0,'P = 2(l+w) → 36 = 2(l+7) → l+7 = 18 → l = 11 cm.','easy',1),
('Mathematics',1,'mcq','Variation',2021,'y varies inversely as x. If y=8 when x=3, find x when y=12:','["2","4","6","9"]',0,'k = xy = 8×3 = 24. When y=12: x = 24/12 = 2.','medium',1);

