-- ENGLISH LANGUAGE — 50 MCQ (Paper 1)
-- ============================================================
INSERT INTO questions (subject, paper_number, question_type, topic, year, question_text, options, correct_answer_index, explanation, difficulty, marks) VALUES

('English Language',1,'mcq','Grammar',2022,'Select the correct sentence:','["He don''t know the answer.","He doesn''t knows the answer.","He doesn''t know the answer.","He do not knows the answer."]',2,'With third person singular subject (He), use "doesn''t" + base verb: "He doesn''t know."','easy',1),
('English Language',1,'mcq','Vocabulary',2021,'Choose the word closest in meaning to "meticulous":','["Careless","Extremely careful","Slow","Adventurous"]',1,'"Meticulous" means extremely careful and precise, especially about small details.','medium',1),
('English Language',1,'mcq','Grammar',2020,'The plural of "phenomenon" is:','["Phenomenons","Phenomenas","Phenomena","Phenomenen"]',2,'The correct Latin-derived plural of phenomenon is "phenomena".','medium',1),
('English Language',1,'mcq','Idioms',2022,'"To bite the bullet" means:','["To eat ammunition","To endure a painful situation bravely","To speak harshly","To argue violently"]',1,'This idiom means to endure a painful or difficult situation with courage.','medium',1),
('English Language',1,'mcq','Synonyms',2021,'Choose the synonym of "garrulous":','["Quiet","Talkative","Aggressive","Intelligent"]',1,'"Garrulous" means excessively talkative, especially about trivial things.','hard',1),
('English Language',1,'mcq','Antonyms',2022,'The antonym of "magnanimous" is:','["Generous","Petty","Kind","Brave"]',1,'"Magnanimous" means generous and forgiving. Its antonym is "petty" (small-minded, ungenerous).','hard',1),
('English Language',1,'mcq','Grammar',2020,'Choose the correct form: The jury ___ reached a verdict.','["have","has","are","were"]',1,'In British English, collective nouns like "jury" take singular verbs: "has reached."','medium',1),
('English Language',1,'mcq','Tenses',2021,'She ___ for three hours before the doctor arrived.','["waited","has waited","had been waiting","is waiting"]',2,'Past perfect continuous: an action that was ongoing before another past action.','hard',1),
('English Language',1,'mcq','Vocabulary',2022,'The word "verbose" describes someone who:','["Is brief and direct","Uses too many words","Speaks quietly","Is aggressive"]',1,'"Verbose" means using more words than necessary; long-winded.','medium',1),
('English Language',1,'mcq','Phonetics',2020,'In which word is the underlined letter silent? br(e)ath, (k)nife, cru(s)h, fl(a)g','["breath","knife","crush","flag"]',1,'The "k" in "knife" is silent. It is not pronounced.','easy',1),
('English Language',1,'mcq','Grammar',2021,'Identify the passive voice: ','["The boy kicked the ball.","The ball was kicked by the boy.","He is kicking the ball.","She kicks the ball."]',1,'Passive voice: subject receives the action. "The ball was kicked by the boy" — the ball receives the action.','easy',1),
('English Language',1,'mcq','Comprehension',2022,'A word that sounds like another but has different meaning and spelling is called a:','["Synonym","Antonym","Homophone","Homonym"]',2,'A homophone sounds the same as another word but has a different meaning and spelling (e.g. "their/there").','medium',1),
('English Language',1,'mcq','Vocabulary',2020,'Choose the word that best fills the blank: The evidence was ___ — it could not be denied.','["dubious","irrefutable","ambiguous","tentative"]',1,'"Irrefutable" means impossible to deny or disprove — it fits "could not be denied."','medium',1),
('English Language',1,'mcq','Grammar',2021,'Which sentence has a split infinitive?','["She decided to go quickly.","She decided to quickly go.","She quickly decided to go.","She decided quickly to go."]',1,'A split infinitive places a word between "to" and the verb: "to quickly go."','hard',1),
('English Language',1,'mcq','Tenses',2022,'By next year, they ___ the new school.','["will build","will have built","are building","have built"]',1,'Future perfect: will have built — an action to be completed by a future time.','medium',1),
('English Language',1,'mcq','Idioms',2020,'"To have feet of clay" means:','["To walk slowly","To have unsuspected weaknesses","To be very poor","To have dirty feet"]',1,'This idiom means to have hidden flaws or weaknesses, especially in an admired person.','hard',1),
('English Language',1,'mcq','Grammar',2021,'Choose the correct preposition: She has been ill ___ Monday.','["for","since","from","during"]',1,'"Since" is used with a specific point in time: "since Monday."','easy',1),
('English Language',1,'mcq','Comprehension',2022,'The main purpose of a topic sentence in a paragraph is to:','["Conclude the paragraph","State the main idea","Provide evidence","Create suspense"]',1,'A topic sentence introduces the central idea that the rest of the paragraph develops.','easy',1),
('English Language',1,'mcq','Vocabulary',2020,'The word "altruistic" means:','["Self-serving","Unselfishly concerned for others","Extremely wealthy","Very intelligent"]',1,'"Altruistic" describes unselfish concern for the welfare of others.','hard',1),
('English Language',1,'mcq','Phonetics',2021,'Which word has the stress on the FIRST syllable?','["Photograph","Photography","Photographic","Photographer"]',0,'"PHOtograph" — stress on first syllable. The others all stress the second syllable.','medium',1),
('English Language',1,'mcq','Grammar',2022,'Choose the correctly punctuated sentence:','["Its raining outside.","Its'' raining outside.","It''s raining outside.","Its raining, outside."]',2,'"It''s" is the contraction of "it is" — the apostrophe replaces the missing letter.','easy',1),
('English Language',1,'mcq','Vocabulary',2020,'To "prevaricate" means:','["To speak the truth directly","To speak evasively to avoid commitment","To predict the future","To argue loudly"]',1,'"Prevaricate" means to speak or act evasively in order to hide the truth.','hard',1),
('English Language',1,'mcq','Grammar',2021,'Select the sentence with correct subject-verb agreement:','["The team are playing well.","The team is playing well.","The team plays good.","The team play well."]',1,'When "team" is treated as a single unit (common in American English), use "is."','medium',1),
('English Language',1,'mcq','Tenses',2022,'I ___ him since we were children.','["know","knew","have known","had known"]',2,'Present perfect: "have known" — an action/state that started in the past and continues now.','medium',1),
('English Language',1,'mcq','Comprehension',2020,'When an author implies something without stating it directly, this is called:','["Explicit meaning","Inference","Denotation","Allusion"]',1,'Inference is the process of drawing conclusions from indirect evidence in a text.','medium',1),
('English Language',1,'mcq','Grammar',2021,'A word that modifies a verb, adjective, or another adverb is a:','["Noun","Adjective","Adverb","Preposition"]',2,'An adverb modifies verbs, adjectives, or other adverbs (e.g. quickly, very, extremely).','easy',1),
('English Language',1,'mcq','Idioms',2022,'"A blessing in disguise" means:','["A hidden gift","Something good that seems bad at first","A religious miracle","An unexpected punishment"]',1,'This idiom describes something that appears negative but turns out to be beneficial.','easy',1),
('English Language',1,'mcq','Vocabulary',2020,'"Enigmatic" means:','["Very simple","Difficult to understand or interpret","Extremely loud","Well organised"]',1,'"Enigmatic" describes something mysterious or puzzling — difficult to understand.','medium',1),
('English Language',1,'mcq','Grammar',2022,'Choose the sentence with a relative clause:','["She sings beautifully.","The man who called you is here.","They arrived late.","Run quickly."]',1,'"who called you" is a relative clause — it modifies "the man" using a relative pronoun.','medium',1),
('English Language',1,'mcq','Phonetics',2021,'Which pair are homophones?','["Bare / Beer","Bear / Bare","Meet / Meat","Goal / Gaol"]',2,'"Meet" and "meat" are homophones — they sound identical but have different spellings and meanings.','medium',1),
('English Language',1,'mcq','Grammar',2020,'The superlative form of "good" is:','["Gooder","Goodest","Better","Best"]',3,'The superlative of "good" is "best" (irregular form).','easy',1),
('English Language',1,'mcq','Tenses',2022,'He ___ television when I arrived.','["watched","is watching","was watching","has watched"]',2,'Past continuous: "was watching" — an action in progress when another past event occurred.','medium',1),
('English Language',1,'mcq','Vocabulary',2021,'The word "taciturn" describes someone who is:','["Very cheerful","Reserved and says little","Extremely loud","Well-read"]',1,'"Taciturn" means habitually silent, reserved, or uncommunicative.','hard',1),
('English Language',1,'mcq','Grammar',2020,'A phrase that acts as a noun in a sentence is a:','["Adjectival phrase","Noun phrase","Adverbial phrase","Verb phrase"]',1,'A noun phrase functions as the subject or object of a verb, acting as a noun.','medium',1),
('English Language',1,'mcq','Comprehension',2021,'The author''s overall attitude toward the subject of a piece of writing is called:','["Theme","Mood","Tone","Style"]',2,'"Tone" refers to the author''s attitude toward the subject, revealed through word choice.','medium',1),
('English Language',1,'mcq','Idioms',2022,'"To beat around the bush" means:','["To garden enthusiastically","To avoid the main topic","To work very hard","To defeat someone easily"]',1,'This idiom means to avoid getting to the main point; to talk around a subject.','easy',1),
('English Language',1,'mcq','Grammar',2021,'Which sentence is grammatically correct?','["Neither of the boys were present.","Neither of the boys was present.","Neither of the boy was present.","Neither boys were present."]',1,'"Neither" takes a singular verb: "Neither of the boys was present."','medium',1),
('English Language',1,'mcq','Vocabulary',2022,'"Plausible" means:','["Certainly true","Impossible","Seeming reasonable or likely","Completely false"]',2,'"Plausible" means appearing reasonable or probable, though not necessarily true.','medium',1),
('English Language',1,'mcq','Tenses',2020,'The children ___ in the garden now.','["played","play","are playing","were playing"]',2,'"Now" signals present continuous tense: "are playing."','easy',1),
('English Language',1,'mcq','Grammar',2022,'Choose the sentence without a grammatical error:','["I should of gone.","I should have went.","I should have gone.","I should had gone."]',2,'"Should have gone" is the correct form. "Of" cannot replace "have"; "went" cannot follow "have."','medium',1),
('English Language',1,'mcq','Comprehension',2021,'Figurative language that compares two unlike things using "like" or "as" is a:','["Metaphor","Simile","Hyperbole","Personification"]',1,'A simile uses "like" or "as" to compare: e.g. "brave as a lion."','easy',1),
('English Language',1,'mcq','Vocabulary',2020,'The word "deprecated" most nearly means:','["Highly valued","Strongly disapproved of","Repaired","Extended"]',1,'"Deprecated" means expressed disapproval of; regarded as obsolete or undesirable.','hard',1),
('English Language',1,'mcq','Phonetics',2022,'In "thorough," the letters "ough" are pronounced:','["As in tough","As in through","As in /uh/","As in cough"]',2,'In "thorough," "ough" makes the /uh/ sound — /ˈθʌr.ə/.','hard',1),
('English Language',1,'mcq','Grammar',2021,'The subject of "Running every day improves health" is:','["Running every day","every day","improves","health"]',0,'"Running every day" is a gerund phrase acting as the subject of the sentence.','medium',1),
('English Language',1,'mcq','Tenses',2022,'She has lived in Monrovia ___ 2010.','["for","since","during","from"]',1,'"Since" is used with a specific time point: "since 2010."','easy',1),
('English Language',1,'mcq','Vocabulary',2020,'"Concise" writing is:','["Long and detailed","Brief and clear","Vague and uncertain","Elaborate and decorative"]',1,'"Concise" means expressing much in few words — brief and clear.','easy',1),
('English Language',1,'mcq','Grammar',2022,'Identify the gerund phrase: "She enjoys reading long novels."','["She enjoys","enjoys reading","reading long novels","long novels"]',2,'"Reading long novels" is a gerund phrase (verb used as noun) acting as the object of "enjoys."','medium',1),
('English Language',1,'mcq','Comprehension',2021,'The climax of a story is:','["The introduction of characters","The resolution of the conflict","The point of highest tension","The falling action"]',2,'The climax is the moment of highest tension or turning point in the narrative.','easy',1),
('English Language',1,'mcq','Idioms',2020,'"To call it a day" means:','["To name a day","To decide to stop working","To celebrate","To make an appointment"]',1,'This idiom means to stop what you are doing for the rest of the day; to decide to quit.','easy',1),
('English Language',1,'mcq','Grammar',2022,'Choose the correct reflexive pronoun: She hurt ___ while cooking.','["her","hers","herself","she"]',2,'Reflexive pronoun: the subject and object refer to the same person — "herself."','easy',1);

-- ============================================================
-- BIOLOGY — 50 MCQ (Paper 1)
-- ============================================================
INSERT INTO questions (subject, paper_number, question_type, topic, year, question_text, options, correct_answer_index, explanation, difficulty, marks) VALUES

('Biology',1,'mcq','Cell Biology',2022,'Which organelle contains the genetic material (DNA) of a cell?','["Mitochondria","Ribosome","Nucleus","Vacuole"]',2,'The nucleus contains the cell''s DNA in the form of chromosomes, controlling cell activities.','easy',1),
('Biology',1,'mcq','Cell Biology',2021,'The process by which water moves across a semi-permeable membrane from a region of high water concentration to low is:','["Diffusion","Active transport","Osmosis","Facilitated diffusion"]',2,'Osmosis is the specific movement of water molecules across a partially permeable membrane along a concentration gradient.','easy',1),
('Biology',1,'mcq','Nutrition',2022,'Which vitamin is produced in the skin when exposed to sunlight?','["Vitamin A","Vitamin B12","Vitamin C","Vitamin D"]',3,'Sunlight (UV radiation) triggers the synthesis of Vitamin D in the skin from cholesterol.','easy',1),
('Biology',1,'mcq','Respiration',2021,'The equation for aerobic respiration is:','["C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ATP","C₆H₁₂O₆ → 2C₂H₅OH + 2CO₂","6CO₂ + 6H₂O → C₆H₁₂O₆ + 6O₂","C₆H₁₂O₆ + 6H₂O → 6CO₂ + 12H₂"]',0,'Aerobic respiration: glucose + oxygen → carbon dioxide + water + ATP energy.','medium',1),
('Biology',1,'mcq','Genetics',2022,'A gene is best defined as:','["A chromosome","A segment of DNA that codes for a specific protein","The entire genome","A protein in the nucleus"]',1,'A gene is a specific sequence of DNA bases that codes for the production of a particular protein.','medium',1),
('Biology',1,'mcq','Ecology',2021,'Which level of a food chain contains the most energy?','["Tertiary consumers","Secondary consumers","Primary consumers","Producers"]',3,'Energy flows from producers → consumers. Producers (plants) contain the most energy; it is lost at each trophic level.','medium',1),
('Biology',1,'mcq','Human Biology',2022,'The part of the brain that controls balance and coordination is the:','["Cerebrum","Cerebellum","Medulla oblongata","Hypothalamus"]',1,'The cerebellum coordinates muscle movements, balance, and posture.','medium',1),
('Biology',1,'mcq','Photosynthesis',2020,'Which gas is absorbed by plants during photosynthesis?','["Oxygen","Nitrogen","Carbon dioxide","Hydrogen"]',2,'Photosynthesis absorbs CO₂ from the air and uses it with water and sunlight to make glucose.','easy',1),
('Biology',1,'mcq','Reproduction',2021,'In humans, fertilisation normally occurs in the:','["Uterus","Ovary","Fallopian tube","Cervix"]',2,'The sperm meets the egg in the fallopian tube (oviduct), where fertilisation takes place.','medium',1),
('Biology',1,'mcq','Cell Biology',2022,'Which of the following is found in plant cells but NOT in animal cells?','["Mitochondria","Cell membrane","Cell wall","Ribosome"]',2,'Plant cells have a rigid cell wall made of cellulose; animal cells do not.','easy',1),
('Biology',1,'mcq','Genetics',2020,'If a pea plant heterozygous for height (Tt) is crossed with a short plant (tt), the expected ratio of tall to short offspring is:','["3:1","1:1","2:1","4:0"]',1,'Tt × tt: offspring are Tt (tall) and tt (short) in equal numbers — ratio 1:1.','medium',1),
('Biology',1,'mcq','Ecology',2022,'Organisms that break down dead organic matter into simpler substances are called:','["Producers","Consumers","Decomposers","Parasites"]',2,'Decomposers (bacteria and fungi) recycle nutrients by breaking down dead material.','easy',1),
('Biology',1,'mcq','Human Biology',2021,'Which blood type is the universal donor?','["AB","A","B","O"]',3,'Blood type O negative lacks A, B, and Rh antigens, so it can be given to most patients.','medium',1),
('Biology',1,'mcq','Nutrition',2022,'The enzyme that digests proteins in the stomach is:','["Amylase","Lipase","Pepsin","Trypsin"]',2,'Pepsin is secreted in the stomach and breaks down proteins into smaller peptides.','medium',1),
('Biology',1,'mcq','Evolution',2021,'Natural selection acts on:','["Genotype only","Phenotype only","Both genotype and phenotype","Neither"]',1,'Natural selection acts on the phenotype (observable traits) — organisms with advantageous traits survive and reproduce.','hard',1),
('Biology',1,'mcq','Classification',2022,'The five kingdoms of living things include all EXCEPT:','["Monera","Protista","Fungi","Mineral"]',3,'The five kingdoms are: Monera, Protista, Fungi, Plantae, Animalia. Mineral is not a kingdom.','easy',1),
('Biology',1,'mcq','Cell Biology',2020,'Mitosis results in:','["Two genetically identical daughter cells","Four haploid cells","Two haploid cells","One diploid and one haploid cell"]',0,'Mitosis produces two genetically identical diploid daughter cells — used for growth and repair.','medium',1),
('Biology',1,'mcq','Ecology',2021,'The abiotic factors in an ecosystem include:','["Plants and animals","Temperature, light, and water","Bacteria and fungi","Predators and prey"]',1,'Abiotic factors are non-living physical and chemical components: temperature, water, light, soil, etc.','easy',1),
('Biology',1,'mcq','Human Biology',2022,'The hormone that regulates blood glucose levels by lowering it is:','["Glucagon","Adrenaline","Insulin","Thyroxine"]',2,'Insulin is produced by the pancreas and lowers blood glucose by promoting cellular uptake of glucose.','medium',1),
('Biology',1,'mcq','Photosynthesis',2021,'The light-dependent reactions of photosynthesis take place in the:','["Stroma","Thylakoid membranes","Cytoplasm","Nucleus"]',1,'The light-dependent reactions occur in the thylakoid membranes of the chloroplast where chlorophyll is located.','hard',1),
('Biology',1,'mcq','Genetics',2022,'The term "allele" refers to:','["A type of chromosome","Different forms of the same gene","A type of protein","The full set of chromosomes"]',1,'Alleles are alternative forms of a gene that occupy the same position (locus) on homologous chromosomes.','medium',1),
('Biology',1,'mcq','Human Biology',2020,'The function of red blood cells is to:','["Fight infection","Carry oxygen around the body","Produce antibodies","Aid blood clotting"]',1,'Red blood cells contain haemoglobin which binds to oxygen and transports it from lungs to body tissues.','easy',1),
('Biology',1,'mcq','Ecology',2022,'A relationship in which one organism benefits and the other is harmed is called:','["Mutualism","Commensalism","Parasitism","Symbiosis"]',2,'In parasitism, the parasite benefits at the expense of the host, which is harmed.','easy',1),
('Biology',1,'mcq','Cell Biology',2021,'The semi-permeable membrane in plant cells that allows selective passage of substances is the:','["Cell wall","Tonoplast","Plasma membrane","Nuclear envelope"]',2,'The plasma membrane (cell surface membrane) is selectively permeable, controlling what enters and leaves.','medium',1),
('Biology',1,'mcq','Nutrition',2022,'Scurvy is caused by a deficiency of:','["Vitamin A","Vitamin B1","Vitamin C","Vitamin D"]',2,'Scurvy results from Vitamin C deficiency, leading to swollen gums, fatigue, and slow wound healing.','easy',1),
('Biology',1,'mcq','Reproduction',2020,'Which type of reproduction produces offspring genetically identical to the parent?','["Sexual reproduction","Asexual reproduction","Cross-pollination","Fertilisation"]',1,'Asexual reproduction (e.g. binary fission, budding) produces genetically identical offspring (clones).','easy',1),
('Biology',1,'mcq','Human Biology',2022,'The organ in the body responsible for producing bile is the:','["Pancreas","Stomach","Liver","Gallbladder"]',2,'The liver produces bile. The gallbladder stores and releases bile into the small intestine.','medium',1),
('Biology',1,'mcq','Photosynthesis',2021,'Which pigment in leaves is responsible for absorbing light for photosynthesis?','["Xanthophyll","Carotene","Chlorophyll","Anthocyanin"]',2,'Chlorophyll is the primary photosynthetic pigment that absorbs red and blue light, reflecting green.','easy',1),
('Biology',1,'mcq','Ecology',2022,'The total mass of living organisms in a given area at a given time is called:','["Biodiversity","Biomass","Population density","Carrying capacity"]',1,'Biomass is the total dry mass of organisms in an area — used to measure productivity at each trophic level.','medium',1),
('Biology',1,'mcq','Cell Biology',2020,'Meiosis produces cells with:','["The same chromosome number as the parent","Half the chromosome number of the parent","Twice the chromosome number","No chromosomes"]',1,'Meiosis (reduction division) halves the chromosome number, producing haploid gametes.','medium',1),
('Biology',1,'mcq','Genetics',2021,'In ABO blood grouping, a person with genotype IAi has blood type:','["AB","B","A","O"]',2,'IA is dominant over i. A person with IAi expresses blood type A.','hard',1),
('Biology',1,'mcq','Human Biology',2022,'The part of the nephron where most reabsorption of water and nutrients occurs is the:','["Glomerulus","Bowman''s capsule","Loop of Henle","Proximal convoluted tubule"]',3,'The proximal convoluted tubule reabsorbs most glucose, amino acids, water, and ions back into the blood.','hard',1),
('Biology',1,'mcq','Nutrition',2021,'Which mineral is essential for the formation of haemoglobin?','["Calcium","Iron","Phosphorus","Sodium"]',1,'Iron is a key component of haemoglobin, the oxygen-carrying protein in red blood cells.','easy',1),
('Biology',1,'mcq','Ecology',2022,'Carbon dioxide is returned to the atmosphere through all of the following EXCEPT:','["Respiration","Combustion","Photosynthesis","Decomposition"]',2,'Photosynthesis removes CO₂ from the atmosphere. Respiration, combustion, and decomposition all release CO₂.','medium',1),
('Biology',1,'mcq','Classification',2021,'Viruses are NOT classified as living organisms because they:','["Are very small","Cannot be seen","Cannot reproduce on their own","Live inside other organisms"]',2,'Viruses lack cell structure and cannot reproduce independently — they require a host cell''s machinery.','medium',1),
('Biology',1,'mcq','Human Biology',2020,'The hormone responsible for the development of secondary sexual characteristics in females is:','["Testosterone","Progesterone","Oestrogen","FSH"]',2,'Oestrogen is the primary female sex hormone responsible for secondary sexual characteristics and the menstrual cycle.','medium',1),
('Biology',1,'mcq','Cell Biology',2022,'The fluid inside the cell (excluding the nucleus) is called:','["Nucleoplasm","Cytoplasm","Sap","Plasma"]',1,'Cytoplasm is the gel-like fluid that fills the cell and contains organelles.','easy',1),
('Biology',1,'mcq','Ecology',2021,'Which gas makes up approximately 78% of the atmosphere?','["Oxygen","Carbon dioxide","Nitrogen","Argon"]',2,'Nitrogen (N₂) makes up about 78% of the atmosphere, oxygen about 21%.','easy',1),
('Biology',1,'mcq','Reproduction',2022,'The process by which a mature follicle releases an egg from the ovary is called:','["Fertilisation","Menstruation","Ovulation","Implantation"]',2,'Ovulation is the release of a mature egg (ovum) from the ovary, typically around day 14 of the cycle.','easy',1),
('Biology',1,'mcq','Genetics',2020,'The carrier of genetic information from the nucleus to the ribosome is:','["DNA","mRNA","tRNA","rRNA"]',1,'Messenger RNA (mRNA) carries the genetic code from the nucleus to the ribosomes where proteins are made.','medium',1),
('Biology',1,'mcq','Nutrition',2022,'The process of breaking down large food molecules into smaller ones is called:','["Absorption","Assimilation","Digestion","Egestion"]',2,'Digestion is the mechanical and chemical breakdown of food into molecules small enough to be absorbed.','easy',1),
('Biology',1,'mcq','Human Biology',2021,'Which part of the eye is responsible for colour vision?','["Rods","Cones","Optic nerve","Iris"]',1,'Cones are photoreceptors concentrated in the fovea that detect colour (red, green, blue).','medium',1),
('Biology',1,'mcq','Cell Biology',2022,'ATP stands for:','["Adenine triphosphate","Adenosine triphosphate","Amino triphosphate","Adenosine triple protein"]',1,'ATP (Adenosine Triphosphate) is the universal energy currency of all living cells.','easy',1),
('Biology',1,'mcq','Ecology',2020,'Acid rain is primarily caused by emissions of:','["Carbon dioxide and methane","Sulphur dioxide and nitrogen oxides","Oxygen and water vapour","CFCs and ozone"]',1,'SO₂ and NOₓ from burning fossil fuels dissolve in rain to form sulphuric and nitric acids.','medium',1),
('Biology',1,'mcq','Genetics',2021,'A mutation is:','["A change in behaviour","A permanent change in the DNA sequence","A type of cell division","A method of reproduction"]',1,'A mutation is a permanent alteration in the nucleotide sequence of DNA — can be harmful, neutral, or beneficial.','medium',1),
('Biology',1,'mcq','Human Biology',2022,'The function of the alveoli in the lungs is to:','["Produce mucus","Filter dust particles","Exchange gases between air and blood","Warm the incoming air"]',2,'Alveoli are tiny air sacs with thin walls and rich blood supply, maximising gas exchange surface area.','easy',1),
('Biology',1,'mcq','Nutrition',2020,'Enzyme action is affected by all of the following EXCEPT:','["Temperature","pH","Substrate concentration","Colour of the substrate"]',3,'Enzymes are affected by temperature, pH, substrate/enzyme concentration. Colour of substrate has no effect.','medium',1),
('Biology',1,'mcq','Photosynthesis',2022,'The Calvin cycle (light-independent reactions) produces:','["ATP only","Oxygen","Glucose (sugar)","Water"]',2,'The Calvin cycle uses ATP and NADPH from the light reactions to fix CO₂ and produce G3P, which forms glucose.','hard',1),
('Biology',1,'mcq','Ecology',2021,'An organism that eats only plants is called a:','["Carnivore","Omnivore","Herbivore","Detritivore"]',2,'A herbivore is an organism that feeds exclusively on plants — it is a primary consumer.','easy',1),
('Biology',1,'mcq','Classification',2022,'Which of the following is an example of a mammal?','["Frog","Snake","Bat","Crocodile"]',2,'A bat is a mammal — warm-blooded, has fur/hair, and suckles young. The others are reptiles or amphibians.','easy',1);


-- ============================================================
-- CHEMISTRY — 50 MCQ (Paper 1)
-- ============================================================
INSERT INTO questions (subject, paper_number, question_type, topic, year, question_text, options, correct_answer_index, explanation, difficulty, marks) VALUES

('Chemistry',1,'mcq','Atomic Structure',2022,'The number of neutrons in an atom of ¹⁴₆C is:','["6","8","14","20"]',1,'Neutrons = Mass number - Atomic number = 14 - 6 = 8.','easy',1),
('Chemistry',1,'mcq','Periodic Table',2021,'Elements in Group 1 of the periodic table are called:','["Noble gases","Halogens","Alkali metals","Transition metals"]',2,'Group 1 elements (Li, Na, K, Rb, Cs, Fr) are alkali metals — highly reactive with water.','easy',1),
('Chemistry',1,'mcq','Chemical Bonding',2022,'A covalent bond is formed by:','["Transfer of electrons","Sharing of electron pairs","Attraction between ions","Metallic lattice"]',1,'Covalent bonds form when two atoms share one or more pairs of electrons.','easy',1),
('Chemistry',1,'mcq','Moles',2021,'How many moles are in 44 g of CO₂? (C=12, O=16)','["0.5","1","2","4"]',1,'Molar mass of CO₂ = 12 + 32 = 44 g/mol. Moles = 44/44 = 1 mol.','easy',1),
('Chemistry',1,'mcq','Acids and Bases',2022,'A solution with pH 2 is:','["Strongly alkaline","Weakly alkaline","Neutral","Strongly acidic"]',3,'pH 2 is well below 7 (neutral), indicating a strongly acidic solution.','easy',1),
('Chemistry',1,'mcq','Organic Chemistry',2021,'The functional group of alcohols is:','["-COOH","-OH","-NH₂","-CHO"]',1,'Alcohols contain the hydroxyl group (-OH) bonded to a carbon atom.','easy',1),
('Chemistry',1,'mcq','Reactions',2022,'In the reaction: Zn + H₂SO₄ → ZnSO₄ + H₂, zinc is:','["Oxidised","Reduced","A catalyst","Unchanged"]',0,'Zinc loses electrons (oxidation state increases from 0 to +2) — it is oxidised.','medium',1),
('Chemistry',1,'mcq','Electrolysis',2020,'The electrode connected to the positive terminal of the battery in electrolysis is the:','["Cathode","Anode","Electrode","Electrolyte"]',1,'The anode (positive electrode) attracts negatively charged ions (anions) during electrolysis.','easy',1),
('Chemistry',1,'mcq','Gases',2021,'Which gas is produced when a carbonate reacts with a dilute acid?','["Hydrogen","Oxygen","Carbon dioxide","Sulphur dioxide"]',2,'Carbonate + acid → salt + water + CO₂. The fizzing is caused by CO₂ gas being released.','easy',1),
('Chemistry',1,'mcq','Periodic Table',2022,'Which group of elements is the least reactive?','["Group 1","Group 7","Group 0 (Noble gases)","Group 2"]',2,'Noble gases (Group 0/18) have full outer electron shells, making them almost completely unreactive.','easy',1),
('Chemistry',1,'mcq','Atomic Structure',2021,'An ion with 11 protons and 10 electrons has a charge of:','["-1","+1","+2","-2"]',1,'11 protons (+11) and 10 electrons (-10): net charge = +1 (sodium ion, Na⁺).','medium',1),
('Chemistry',1,'mcq','Chemical Bonding',2022,'The shape of a water molecule (H₂O) is:','["Linear","Trigonal planar","V-shaped (bent)","Tetrahedral"]',2,'Water has a V-shaped (bent) molecular geometry due to two lone pairs on the oxygen atom.','medium',1),
('Chemistry',1,'mcq','Organic Chemistry',2020,'Ethanol belongs to which homologous series?','["Alkanes","Alkenes","Alcohols","Carboxylic acids"]',2,'Ethanol (C₂H₅OH) contains the -OH group and belongs to the alcohols homologous series.','easy',1),
('Chemistry',1,'mcq','Reactions',2021,'The chemical formula for calcium carbonate (limestone) is:','["CaCO₂","Ca₂CO₃","CaCO₃","Ca(CO₃)₂"]',2,'Calcium carbonate is CaCO₃ — Ca²⁺ and CO₃²⁻ ions in a 1:1 ratio.','easy',1),
('Chemistry',1,'mcq','Moles',2022,'Avogadro''s constant is approximately:','["6.02 × 10²³","3.01 × 10²³","6.02 × 10²²","1.66 × 10⁻²⁴"]',0,'Avogadro''s number (6.02 × 10²³) is the number of particles in one mole of a substance.','easy',1),
('Chemistry',1,'mcq','Acids and Bases',2021,'The neutralisation reaction between an acid and a base produces:','["Only water","Salt and water","Only salt","Gas and salt"]',1,'Acid + Base → Salt + Water. This is the definition of neutralisation.','easy',1),
('Chemistry',1,'mcq','Electrolysis',2022,'During electrolysis of molten lead bromide, lead is deposited at the:','["Anode","Electrolyte","Cathode","Both electrodes"]',2,'Pb²⁺ ions (positive) are attracted to the cathode (negative electrode) where they gain electrons and are reduced to lead metal.','medium',1),
('Chemistry',1,'mcq','Atomic Structure',2020,'The outermost electrons in an atom are called:','["Core electrons","Nuclear electrons","Valence electrons","Neutrons"]',2,'Valence electrons are in the outermost shell and determine the chemical properties of an element.','easy',1),
('Chemistry',1,'mcq','Environmental Chemistry',2021,'Which gas is primarily responsible for the greenhouse effect?','["Nitrogen","Oxygen","Carbon dioxide","Hydrogen"]',2,'CO₂ and other greenhouse gases trap heat from the sun in the atmosphere, causing global warming.','easy',1),
('Chemistry',1,'mcq','Periodic Table',2022,'As you move across Period 3 from left to right, the atomic radius:','["Increases","Decreases","Stays the same","First increases then decreases"]',1,'Across a period, the number of protons increases, pulling electrons closer — atomic radius decreases.','hard',1),
('Chemistry',1,'mcq','Organic Chemistry',2021,'Which type of reaction occurs when bromine water is decolourised by an alkene?','["Substitution","Elimination","Addition","Combustion"]',2,'Alkenes undergo addition reactions. Bromine adds across the double bond, decolourising brown Br₂.','medium',1),
('Chemistry',1,'mcq','Reactions',2022,'Rusting of iron requires both:','["Water only","Oxygen only","Water and oxygen","Acid and water"]',2,'Rusting (oxidation) of iron requires the simultaneous presence of water and oxygen.','easy',1),
('Chemistry',1,'mcq','Moles',2020,'What mass of NaCl (Na=23, Cl=35.5) is in 2 moles?','["58.5 g","117 g","29.25 g","234 g"]',1,'Molar mass of NaCl = 23 + 35.5 = 58.5 g/mol. 2 moles = 2 × 58.5 = 117 g.','medium',1),
('Chemistry',1,'mcq','Acids and Bases',2022,'Which of the following is a weak acid?','["Hydrochloric acid (HCl)","Sulphuric acid (H₂SO₄)","Nitric acid (HNO₃)","Ethanoic acid (CH₃COOH)"]',3,'Ethanoic acid (acetic acid) only partially dissociates in water — it is a weak acid.','medium',1),
('Chemistry',1,'mcq','Chemical Bonding',2021,'Metallic bonding involves:','["Shared electron pairs between two atoms","A sea of delocalised electrons","Transfer of electrons between ions","Van der Waals forces"]',1,'Metallic bonds consist of positive metal ions surrounded by a sea of delocalised (free) electrons.','medium',1),
('Chemistry',1,'mcq','Gases',2022,'At standard temperature and pressure (STP), one mole of any ideal gas occupies:','["22.4 L","22.4 mL","11.2 L","44.8 L"]',0,'At STP (0°C, 1 atm), 1 mole of any ideal gas occupies 22.4 litres (molar volume).','medium',1),
('Chemistry',1,'mcq','Reactions',2021,'A reaction that releases heat to the surroundings is called:','["Endothermic","Exothermic","Reversible","Equilibrium"]',1,'An exothermic reaction releases energy (heat) to the surroundings — ΔH is negative.','easy',1),
('Chemistry',1,'mcq','Organic Chemistry',2022,'The general formula for alkenes is:','["CₙH₂ₙ","CₙH₂ₙ₊₂","CₙH₂ₙ₋₂","CₙH₂ₙ₊₁OH"]',0,'Alkenes (one C=C double bond) have general formula CₙH₂ₙ. Example: ethene C₂H₄.','medium',1),
('Chemistry',1,'mcq','Periodic Table',2020,'Which of the following is a transition metal?','["Sodium","Magnesium","Iron","Calcium"]',2,'Iron (Fe) is a transition metal (Group 8, Period 4). Na, Mg, and Ca are main group metals.','easy',1),
('Chemistry',1,'mcq','Atomic Structure',2022,'Isotopes are atoms of the same element with the same number of protons but different:','["Electrons","Neutrons","Protons","Energy levels"]',1,'Isotopes have the same atomic number (protons) but different mass numbers (due to different neutrons).','easy',1),
('Chemistry',1,'mcq','Electrolysis',2021,'In the electrolysis of dilute sulphuric acid, oxygen is produced at the:','["Cathode","Anode","Both electrodes","Neither electrode"]',1,'At the anode (positive): 4OH⁻ → 2H₂O + O₂ + 4e⁻. Oxygen is released at the anode.','medium',1),
('Chemistry',1,'mcq','Acids and Bases',2022,'A buffer solution is one that:','["Neutralises all acids","Resists changes in pH when small amounts of acid or base are added","Has a pH of exactly 7","Changes colour with pH"]',1,'A buffer solution maintains relatively constant pH when small amounts of acid or alkali are added.','hard',1),
('Chemistry',1,'mcq','Moles',2021,'Concentration is calculated as:','["Mass ÷ Volume","Moles ÷ Volume (in litres)","Moles × Volume","Volume ÷ Moles"]',1,'Concentration (mol/L or mol dm⁻³) = moles of solute ÷ volume of solution in litres.','medium',1),
('Chemistry',1,'mcq','Organic Chemistry',2020,'Fermentation of glucose produces:','["Ethanoic acid and water","Ethanol and carbon dioxide","Methane and water","Propanol and oxygen"]',1,'Fermentation: C₆H₁₂O₆ → 2C₂H₅OH + 2CO₂. Yeast converts glucose to ethanol and CO₂.','medium',1),
('Chemistry',1,'mcq','Chemical Bonding',2022,'The bond angle in a methane (CH₄) molecule is approximately:','["90°","109.5°","120°","180°"]',1,'Methane has tetrahedral geometry with bond angles of 109.5°.','medium',1),
('Chemistry',1,'mcq','Reactions',2021,'A catalyst works by:','["Increasing activation energy","Being consumed in the reaction","Providing an alternative reaction pathway with lower activation energy","Increasing temperature"]',2,'A catalyst provides an alternative reaction pathway with lower activation energy, speeding up the reaction without being consumed.','hard',1),
('Chemistry',1,'mcq','Periodic Table',2022,'The halogens are in Group:','["1","2","6","7"]',3,'Halogens (F, Cl, Br, I, At) are in Group 7 (or Group 17 in the IUPAC system).','easy',1),
('Chemistry',1,'mcq','Gases',2021,'Boyle''s Law states that at constant temperature, the pressure of a gas is:','["Directly proportional to volume","Inversely proportional to volume","Equal to volume","Independent of volume"]',1,'Boyle''s Law: P ∝ 1/V at constant temperature. If volume decreases, pressure increases.','medium',1),
('Chemistry',1,'mcq','Atomic Structure',2022,'Which model of the atom describes electrons in specific energy levels (shells)?','["Dalton''s model","Thomson''s plum pudding model","Rutherford''s nuclear model","Bohr''s model"]',3,'Niels Bohr proposed that electrons orbit the nucleus in fixed energy levels (shells).','medium',1),
('Chemistry',1,'mcq','Organic Chemistry',2021,'Polymers are formed from small repeating units called:','["Isomers","Monomers","Dimers","Oligomers"]',1,'Polymers are long chain molecules formed by linking many small monomer units together (polymerisation).','easy',1),
('Chemistry',1,'mcq','Reactions',2022,'In a reversible reaction at equilibrium, the forward and reverse reactions:','["Have stopped","Occur at equal rates","The forward rate is faster","The reverse rate is faster"]',1,'Dynamic equilibrium: both forward and reverse reactions continue but at equal rates, so concentrations remain constant.','medium',1),
('Chemistry',1,'mcq','Acids and Bases',2020,'Which of the following is an indicator?','["Litmus","Phenolphthalein","Both litmus and phenolphthalein","Hydrochloric acid"]',2,'Both litmus and phenolphthalein are indicators that change colour depending on whether a solution is acidic or alkaline.','easy',1),
('Chemistry',1,'mcq','Moles',2022,'Which of the following has the greatest number of molecules?','["1 mol of H₂","1 mol of N₂","1 mol of CO₂","All have the same number"]',3,'One mole of ANY substance contains 6.02 × 10²³ entities — the same number regardless of the substance.','medium',1),
('Chemistry',1,'mcq','Environmental Chemistry',2021,'Catalytic converters in cars reduce:','["CO₂ emissions","Noise pollution","NOₓ and CO emissions","Fuel consumption"]',2,'Catalytic converters convert harmful NOₓ, CO, and unburned hydrocarbons into N₂, CO₂, and H₂O.','medium',1),
('Chemistry',1,'mcq','Chemical Bonding',2022,'Which substance has the highest melting point?','["Sodium chloride (ionic)","Methane (molecular)","Diamond (covalent network)","Helium (atomic)"]',2,'Diamond has a giant covalent lattice structure with strong C-C bonds throughout — extremely high melting point.','hard',1),
('Chemistry',1,'mcq','Organic Chemistry',2020,'Saponification is the process of making:','["Alcohol from glucose","Soap from fats and alkali","Plastic from monomers","Acid from ester"]',1,'Saponification is the hydrolysis of ester bonds in fats using sodium or potassium hydroxide to produce soap and glycerol.','hard',1),
('Chemistry',1,'mcq','Reactions',2021,'Le Chatelier''s Principle states that when a system at equilibrium is disturbed, it:','["Stops reacting","Shifts to oppose the change","Shifts to increase the change","Remains unchanged"]',1,'Le Chatelier''s Principle: a system at equilibrium responds to a disturbance by shifting to minimise that disturbance.','hard',1),
('Chemistry',1,'mcq','Periodic Table',2022,'Which property generally increases down Group 1?','["Electronegativity","Ionisation energy","Reactivity with water","Melting point"]',2,'Down Group 1, the outer electron is further from the nucleus and more easily lost — reactivity with water increases.','medium',1),
('Chemistry',1,'mcq','Atomic Structure',2020,'The electronic configuration of chlorine (atomic number 17) is:','["2,8,7","2,8,8","2,7,8","2,8,1,6"]',0,'Chlorine has 17 electrons arranged as: 2 in shell 1, 8 in shell 2, 7 in shell 3 = 2,8,7.','medium',1),
('Chemistry',1,'mcq','Gases',2022,'Which gas turns limewater milky?','["Oxygen","Hydrogen","Carbon dioxide","Nitrogen"]',2,'CO₂ reacts with calcium hydroxide (limewater) to form calcium carbonate — a white precipitate.','easy',1);


-- ============================================================
-- PHYSICS — 50 MCQ (Paper 1)
-- ============================================================
INSERT INTO questions (subject, paper_number, question_type, topic, year, question_text, options, correct_answer_index, explanation, difficulty, marks) VALUES

('Physics',1,'mcq','Mechanics',2022,'A car accelerates from 0 to 20 m/s in 5 seconds. Its acceleration is:','["4 m/s²","100 m/s²","0.25 m/s²","25 m/s²"]',0,'a = (v-u)/t = (20-0)/5 = 4 m/s².','easy',1),
('Physics',1,'mcq','Forces',2021,'Newton''s Second Law of Motion states that force equals:','["Mass × Velocity","Mass × Acceleration","Mass × Distance","Velocity × Time"]',1,'F = ma (Force = mass × acceleration). The SI unit of force is the Newton.','easy',1),
('Physics',1,'mcq','Energy',2022,'The kinetic energy of a 2 kg object moving at 3 m/s is:','["6 J","9 J","3 J","12 J"]',1,'KE = ½mv² = ½ × 2 × 3² = ½ × 2 × 9 = 9 J.','easy',1),
('Physics',1,'mcq','Waves',2021,'The frequency of a wave with a period of 0.02 s is:','["0.02 Hz","2 Hz","20 Hz","50 Hz"]',3,'f = 1/T = 1/0.02 = 50 Hz.','medium',1),
('Physics',1,'mcq','Electricity',2022,'Ohm''s Law states that current is:','["Directly proportional to resistance","Inversely proportional to voltage","Directly proportional to voltage (at constant resistance)","Equal to voltage"]',2,'V = IR → I = V/R. Current is directly proportional to voltage when resistance is constant.','easy',1),
('Physics',1,'mcq','Heat',2021,'The specific heat capacity of water is 4200 J/kg°C. Energy to heat 2 kg from 20°C to 50°C:','["84 000 J","126 000 J","252 000 J","42 000 J"]',2,'Q = mcΔT = 2 × 4200 × 30 = 252 000 J.','medium',1),
('Physics',1,'mcq','Optics',2022,'When light passes from air into glass, it:','["Speeds up and bends away from normal","Slows down and bends toward normal","Speeds up and bends toward normal","Maintains the same speed"]',1,'Light slows down in a denser medium (glass) and bends toward the normal — this is refraction.','medium',1),
('Physics',1,'mcq','Mechanics',2020,'A body in equilibrium has:','["Zero velocity only","Zero acceleration only","Both zero velocity and zero acceleration","Net force equal to zero"]',3,'Equilibrium means the net force is zero. The body may still be moving at constant velocity.','medium',1),
('Physics',1,'mcq','Electricity',2021,'In a series circuit, the total resistance of 3Ω and 5Ω resistors is:','["8Ω","15Ω","1.875Ω","0.53Ω"]',0,'Series: R_total = R₁ + R₂ = 3 + 5 = 8Ω.','easy',1),
('Physics',1,'mcq','Magnetism',2022,'The direction of the force on a current-carrying conductor in a magnetic field is given by:','["Lenz''s Law","Fleming''s Left-Hand Rule","Fleming''s Right-Hand Rule","Newton''s Third Law"]',1,'Fleming''s Left-Hand Rule gives the direction of the force (motor effect) on a current-carrying conductor in a magnetic field.','medium',1),
('Physics',1,'mcq','Modern Physics',2021,'Radioactive decay that involves the emission of a helium nucleus (2 protons, 2 neutrons) is:','["Alpha decay","Beta decay","Gamma decay","Neutron emission"]',0,'Alpha (α) radiation consists of a helium nucleus (⁴₂He) — 2 protons and 2 neutrons.','easy',1),
('Physics',1,'mcq','Waves',2022,'Which electromagnetic wave has the shortest wavelength?','["Radio waves","Infrared","Visible light","Gamma rays"]',3,'The electromagnetic spectrum from longest to shortest wavelength: radio, microwave, infrared, visible, UV, X-ray, gamma.','easy',1),
('Physics',1,'mcq','Mechanics',2020,'The gravitational potential energy of a 5 kg object at a height of 10 m (g=10 m/s²) is:','["5 J","50 J","500 J","50 000 J"]',2,'GPE = mgh = 5 × 10 × 10 = 500 J.','easy',1),
('Physics',1,'mcq','Heat',2021,'When a substance melts, the temperature:','["Increases","Decreases","Remains constant","Fluctuates"]',2,'During melting, energy breaks intermolecular bonds without raising temperature — it stays constant at the melting point.','medium',1),
('Physics',1,'mcq','Electricity',2022,'Power in an electrical circuit is:','["V/I","V + I","VI","V²/I²"]',2,'P = VI (power = voltage × current). Also P = I²R = V²/R.','easy',1),
('Physics',1,'mcq','Optics',2020,'A convex lens is also called a:','["Diverging lens","Concave lens","Converging lens","Plane lens"]',2,'A convex lens converges parallel rays to a focal point — it is a converging lens.','easy',1),
('Physics',1,'mcq','Forces',2021,'The moment (turning effect) of a force depends on:','["The force only","The distance only","Both the force and the perpendicular distance from the pivot","Neither force nor distance"]',2,'Moment = Force × perpendicular distance from pivot. Both factors determine the turning effect.','medium',1),
('Physics',1,'mcq','Modern Physics',2022,'In nuclear fission, a heavy nucleus:','["Combines with another nucleus","Splits into smaller nuclei releasing energy","Emits gamma rays only","Gains a neutron and becomes stable"]',1,'Fission is the splitting of a heavy nucleus (e.g. U-235) into lighter nuclei, releasing energy and neutrons.','medium',1),
('Physics',1,'mcq','Waves',2021,'Sound cannot travel through:','["Solids","Liquids","Gases","A vacuum"]',3,'Sound is a mechanical wave requiring a medium to propagate. It cannot travel through a vacuum.','easy',1),
('Physics',1,'mcq','Mechanics',2022,'A spring obeys Hooke''s Law. If a force of 6 N extends it by 3 cm, its spring constant is:','["2 N/cm","0.5 N/cm","18 N/cm","9 N/cm"]',0,'k = F/x = 6/3 = 2 N/cm (or 200 N/m).','medium',1),
('Physics',1,'mcq','Electricity',2020,'A charge of 10 C passes a point in 2 s. The current is:','["20 A","0.2 A","5 A","12 A"]',2,'I = Q/t = 10/2 = 5 A.','easy',1),
('Physics',1,'mcq','Heat',2022,'Heat transfer through a vacuum is possible by:','["Conduction","Convection","Radiation","All three methods"]',2,'Radiation does not require a medium — it can transfer heat through a vacuum (e.g. from the Sun to Earth).','easy',1),
('Physics',1,'mcq','Optics',2021,'The critical angle is the angle of incidence beyond which:','["Refraction occurs","Total internal reflection occurs","Partial reflection occurs","Dispersion occurs"]',1,'When light in a denser medium hits the boundary at an angle greater than the critical angle, total internal reflection occurs.','medium',1),
('Physics',1,'mcq','Forces',2022,'Archimedes'' Principle states that the upthrust on an object in a fluid equals:','["The weight of the object","The volume of fluid","The weight of fluid displaced","The density of the object"]',2,'Upthrust = weight of fluid displaced. This is the basis of buoyancy.','medium',1),
('Physics',1,'mcq','Modern Physics',2021,'Beta-minus (β⁻) decay involves the emission of:','["A helium nucleus","A high-energy photon","An electron from the nucleus","A positron"]',2,'In β⁻ decay, a neutron converts to a proton, releasing an electron (beta particle) and antineutrino.','hard',1),
('Physics',1,'mcq','Mechanics',2022,'Work done is zero when the force and displacement are:','["In the same direction","At 45° to each other","Perpendicular to each other","At 180° to each other"]',2,'W = Fd cosθ. When θ = 90°, cosθ = 0, so W = 0.','medium',1),
('Physics',1,'mcq','Electricity',2021,'The unit of electrical energy is the:','["Watt","Joule","Coulomb","Ampere"]',1,'Electrical energy is measured in Joules (J). 1 J = 1 W × 1 s.','easy',1),
('Physics',1,'mcq','Waves',2020,'The relationship between wave speed, frequency, and wavelength is:','["v = f/λ","v = fλ","v = λ/f","f = vλ"]',1,'Wave equation: v = fλ (speed = frequency × wavelength).','easy',1),
('Physics',1,'mcq','Magnetism',2022,'An electromagnet can be made stronger by:','["Using a shorter wire","Decreasing the current","Increasing the number of coil turns","Using an aluminium core"]',2,'An electromagnet is strengthened by increasing turns, increasing current, or using a soft iron core.','medium',1),
('Physics',1,'mcq','Heat',2021,'The process by which heat travels through a liquid due to movement of the fluid itself is:','["Conduction","Convection","Radiation","Evaporation"]',1,'Convection involves the transfer of heat through bulk movement of a fluid (liquid or gas).','easy',1),
('Physics',1,'mcq','Mechanics',2022,'The unit of momentum is:','["kg","N","kg m/s","J"]',2,'Momentum p = mv. Units: kg × m/s = kg m/s.','easy',1),
('Physics',1,'mcq','Optics',2020,'The splitting of white light into colours by a prism is called:','["Reflection","Refraction","Dispersion","Diffraction"]',2,'Dispersion occurs because different colours (wavelengths) refract by different amounts in a prism.','easy',1),
('Physics',1,'mcq','Modern Physics',2022,'The half-life of a radioactive substance is the time for:','["All the substance to decay","Half the substance to decay","The activity to double","The substance to become stable"]',1,'Half-life is the time for half of the radioactive nuclei to decay.','easy',1),
('Physics',1,'mcq','Electricity',2021,'In a parallel circuit with two identical 6Ω resistors, the total resistance is:','["12Ω","3Ω","6Ω","2Ω"]',1,'Parallel: 1/R = 1/6 + 1/6 = 2/6 → R = 3Ω.','medium',1),
('Physics',1,'mcq','Forces',2022,'The principle of conservation of momentum states that:','["Momentum is always increasing","Total momentum of a system is constant in the absence of external forces","Objects always move faster after collision","Forces always cause acceleration"]',1,'Conservation of momentum: in a closed system (no external forces), total momentum before = total momentum after collision.','medium',1),
('Physics',1,'mcq','Mechanics',2021,'A ball is thrown vertically upward. At its maximum height, its velocity is:','["Maximum","Equal to initial velocity","Zero","Half the initial velocity"]',2,'At maximum height, the ball momentarily stops before falling — velocity = 0.','easy',1),
('Physics',1,'mcq','Heat',2022,'The Kelvin temperature scale uses what value for absolute zero?','["0°C","−273°C","−100°C","−373°C"]',1,'Absolute zero is 0 K = −273.15°C — the temperature at which all molecular motion theoretically stops.','medium',1),
('Physics',1,'mcq','Waves',2021,'When waves pass from a shallow region to a deep region, their speed:','["Decreases","Remains the same","Increases","Becomes zero"]',2,'Water waves travel faster in deeper water — their speed increases as depth increases.','hard',1),
('Physics',1,'mcq','Electricity',2020,'The device used to measure potential difference (voltage) is a:','["Ammeter","Ohmmeter","Voltmeter","Galvanometer"]',2,'A voltmeter measures potential difference and is connected in PARALLEL with the component.','easy',1),
('Physics',1,'mcq','Magnetism',2021,'Electromagnetic induction occurs when:','["A current flows through a wire","A wire moves in a magnetic field","A magnet is held still near a wire","Two magnets repel each other"]',1,'Electromagnetic induction: an EMF is induced in a conductor when it moves relative to a magnetic field (Faraday''s Law).','medium',1),
('Physics',1,'mcq','Modern Physics',2022,'Nuclear fusion:','["Splits heavy atoms","Joins light nuclei together to release energy","Releases less energy than fission","Occurs in nuclear power stations"]',1,'Fusion is the combining of light nuclei (e.g. hydrogen) to form heavier nuclei — releases enormous energy (powers the Sun).','medium',1),
('Physics',1,'mcq','Mechanics',2022,'The law of conservation of energy states that:','["Energy can be created from nothing","Energy can be destroyed","Energy can neither be created nor destroyed, only converted","Kinetic energy is always conserved"]',2,'Energy cannot be created or destroyed — it can only be converted from one form to another.','easy',1),
('Physics',1,'mcq','Forces',2021,'The terminal velocity of a falling object is reached when:','["Weight equals zero","Air resistance equals weight","The object reaches the ground","Acceleration is maximum"]',1,'Terminal velocity: when weight (downward) equals air resistance (upward), net force = 0, acceleration = 0, speed is constant.','medium',1),
('Physics',1,'mcq','Electricity',2022,'The transformer equation (Vp/Vs = Np/Ns) shows that a step-up transformer:','["Has fewer turns on secondary than primary","Reduces voltage","Has more turns on secondary than primary","Reduces current"]',2,'Step-up transformer: Ns > Np → secondary voltage is higher than primary voltage.','medium',1),
('Physics',1,'mcq','Waves',2020,'Diffraction is most noticeable when the gap width is:','["Much larger than the wavelength","About the same size as the wavelength","Much smaller than the wavelength","Zero"]',1,'Maximum diffraction occurs when the gap width ≈ wavelength of the wave.','hard',1),
('Physics',1,'mcq','Mechanics',2021,'If the mass of an object is doubled while the net force stays the same, the acceleration:','["Doubles","Stays the same","Halves","Quadruples"]',2,'F = ma → a = F/m. If m doubles, a halves (they are inversely proportional at constant force).','medium',1),
('Physics',1,'mcq','Heat',2022,'Evaporation causes cooling because:','["Water expands when it evaporates","Faster-moving molecules leave the liquid, reducing average KE","It absorbs oxygen","Cold air replaces warm air"]',1,'Faster molecules escape during evaporation, lowering the average kinetic energy (temperature) of remaining liquid.','hard',1),
('Physics',1,'mcq','Optics',2021,'The focal length of a lens is the distance from:','["The lens to the object","The lens to the focal point","The object to the image","The principal axis to the lens"]',1,'The focal length is the distance from the optical centre of the lens to the principal focus (focal point).','easy',1),
('Physics',1,'mcq','Electricity',2022,'A device that converts chemical energy into electrical energy is a:','["Motor","Generator","Battery/Cell","Transformer"]',2,'A battery (electrochemical cell) converts chemical energy to electrical energy through redox reactions.','easy',1),
('Physics',1,'mcq','Modern Physics',2021,'Which type of radiation has the greatest penetrating power?','["Alpha (α)","Beta (β)","Gamma (γ)","Neutron"]',2,'Gamma radiation has the greatest penetrating power — it requires thick lead or concrete to stop it.','easy',1);


-- ============================================================
-- ECONOMICS — 50 MCQ (Paper 1)
-- ============================================================
INSERT INTO questions (subject, paper_number, question_type, topic, year, question_text, options, correct_answer_index, explanation, difficulty, marks) VALUES

('Economics',1,'mcq','Basic Concepts',2022,'Economics is primarily concerned with:','["Making money","The allocation of scarce resources among unlimited wants","How to run a business","Government taxation"]',1,'Economics studies how individuals, firms, and governments allocate scarce resources to satisfy unlimited wants.','easy',1),
('Economics',1,'mcq','Demand',2021,'Which of the following would cause the demand curve for a normal good to shift RIGHT?','["A decrease in consumer income","A rise in the price of the good","An increase in consumer income","A rise in the price of a complementary good"]',2,'For normal goods, demand increases as income rises — the demand curve shifts right.','medium',1),
('Economics',1,'mcq','Supply',2022,'A subsidy given to producers will:','["Shift supply left (decrease supply)","Shift supply right (increase supply)","Not affect supply","Only affect demand"]',1,'A subsidy reduces production costs, encouraging more supply — the supply curve shifts right.','medium',1),
('Economics',1,'mcq','Elasticity',2021,'If a 20% rise in price causes a 10% fall in quantity demanded, PED is:','["2","0.5","−0.5","−2"]',2,'PED = %ΔQd / %ΔP = −10/20 = −0.5. Inelastic demand (|PED| < 1).','hard',1),
('Economics',1,'mcq','Market Structures',2022,'A perfectly competitive market has all of the following EXCEPT:','["Many buyers and sellers","Homogeneous products","Barriers to entry","Perfect information"]',2,'Perfect competition has NO barriers to entry — firms can freely enter and exit the market.','medium',1),
('Economics',1,'mcq','National Income',2021,'GDP measures:','["Total value of goods produced by a country''s citizens worldwide","Total value of goods and services produced within a country''s borders in a year","Government spending only","Total exports minus imports"]',1,'GDP (Gross Domestic Product) is the total monetary value of all goods and services produced within a country in a given period.','easy',1),
('Economics',1,'mcq','Money and Banking',2022,'When the central bank raises the interest rate, it generally:','["Increases inflation","Increases borrowing and spending","Reduces inflation by reducing borrowing","Has no effect on the economy"]',2,'Higher interest rates increase the cost of borrowing, reducing spending and investment — this helps control inflation.','medium',1),
('Economics',1,'mcq','Public Finance',2021,'A regressive tax:','["Takes a higher percentage from higher incomes","Takes a lower percentage from higher incomes","Is the same percentage for all incomes","Only taxes corporations"]',1,'A regressive tax takes a higher percentage from lower-income earners and a lower percentage from higher earners.','medium',1),
('Economics',1,'mcq','International Trade',2022,'Comparative advantage means a country should produce goods where it has:','["The lowest absolute cost","The lowest opportunity cost","The highest profit","The most workers"]',1,'Comparative advantage: produce where your opportunity cost is lowest — the basis of international specialisation and trade.','hard',1),
('Economics',1,'mcq','Development Economics',2021,'A developing country typically has:','["High GDP per capita","High literacy rates","Low human development index (HDI)","Advanced industrial sector"]',2,'Developing countries typically have low HDI, indicating low income, education levels, and life expectancy.','easy',1),
('Economics',1,'mcq','Basic Concepts',2022,'The opportunity cost of a decision is:','["The money spent on it","The value of the next best alternative foregone","The total cost of production","The profit from the decision"]',1,'Opportunity cost is the value of the best alternative you give up when making a choice.','easy',1),
('Economics',1,'mcq','Demand',2020,'Two goods are substitutes if:','["A rise in price of one causes demand for the other to fall","A rise in price of one causes demand for the other to rise","They are always purchased together","Their supply always changes together"]',1,'Substitutes: if price of one rises, consumers switch to the other (demand rises). Example: Pepsi and Coca-Cola.','medium',1),
('Economics',1,'mcq','Production',2022,'The law of diminishing returns states that:','["Output always falls when more workers are hired","Total output eventually decreases when variable inputs increase beyond a point","Costs always rise proportionally","Fixed costs decrease as output increases"]',1,'Adding more of a variable input (e.g. labour) to a fixed input eventually yields smaller increases in output.','hard',1),
('Economics',1,'mcq','Market Structures',2021,'A monopoly arises when:','["There are two firms in a market","One firm supplies the entire market with no close substitutes","All firms sell identical products","There are no barriers to entry"]',1,'A monopoly exists when a single seller supplies the entire market, protected by barriers to entry.','easy',1),
('Economics',1,'mcq','National Income',2022,'Which of the following is included in GDP?','["Black market transactions","Government transfer payments (e.g. pensions)","Final goods and services produced","Intermediate goods used in production"]',2,'GDP counts final goods and services only. Transfer payments and intermediate goods are excluded.','hard',1),
('Economics',1,'mcq','Money and Banking',2021,'Commercial banks create money through:','["Printing notes","Lending out deposits (credit creation)","Buying government bonds","Collecting taxes"]',1,'Commercial banks create money by lending out a fraction of deposits — this is called credit creation (fractional reserve banking).','hard',1),
('Economics',1,'mcq','Public Finance',2022,'Government expenditure that is not linked to any service delivery (e.g. pensions, subsidies) is called:','["Capital expenditure","Transfer payments","Tax revenue","Public debt"]',1,'Transfer payments (welfare, pensions, subsidies) are redistributive — no good or service is produced in return.','medium',1),
('Economics',1,'mcq','Inflation',2021,'Cost-push inflation is caused by:','["Excess demand in the economy","Rising production costs (e.g. wages, raw materials)","Increased consumer confidence","Tax cuts"]',1,'Cost-push inflation occurs when production costs rise (e.g. oil prices, wages), forcing firms to raise prices.','medium',1),
('Economics',1,'mcq','Liberia Context',2022,'The dominant export sector in Liberia''s economy has historically been:','["Tourism and services","Manufacturing and textiles","Natural resources — rubber, iron ore, gold","Technology and finance"]',2,'Liberia''s economy has historically been dominated by natural resource exports, particularly rubber (Firestone) and iron ore.','easy',1),
('Economics',1,'mcq','Basic Concepts',2020,'A public good is:','["Any good sold by the government","Non-excludable and non-rival in consumption","A good with positive externalities","A good with inelastic demand"]',1,'Public goods are non-excludable (cannot exclude non-payers) and non-rival (one person''s use doesn''t reduce availability for others).','hard',1),
('Economics',1,'mcq','Demand',2022,'The income effect of a price rise states that:','["Consumer income increases when price rises","A price rise reduces real income, reducing quantity demanded","People buy more when prices rise","Demand is unaffected by income changes"]',1,'When price rises, real purchasing power falls — consumers feel poorer and demand less (income effect).','hard',1),
('Economics',1,'mcq','Supply',2021,'If the cost of raw materials increases, the supply curve will:','["Shift right (increase)","Shift left (decrease)","Not change","Become perfectly elastic"]',1,'Higher raw material costs raise production costs, making firms less willing to supply — supply decreases (shifts left).','medium',1),
('Economics',1,'mcq','Market Structures',2022,'In oligopoly, firms often:','["Act completely independently","Compete solely on price","Engage in non-price competition and may collude","Have no market power"]',2,'Oligopolies are dominated by a few large firms that tend to use non-price competition (advertising, branding) and may collude.','medium',1),
('Economics',1,'mcq','National Income',2021,'The Human Development Index (HDI) measures:','["GDP only","Income, education, and life expectancy","Employment rates","Trade balance"]',1,'HDI combines income per capita, education (literacy/enrolment), and life expectancy into one development measure.','medium',1),
('Economics',1,'mcq','Unemployment',2022,'Structural unemployment occurs when:','["Workers are between jobs","Workers lack skills needed by available jobs","Workers are unemployed seasonally","Demand for goods falls"]',1,'Structural unemployment arises from mismatches between workers'' skills and employer requirements — often due to technological change.','hard',1),
('Economics',1,'mcq','Public Finance',2021,'The main source of government revenue is:','["Borrowing","Foreign aid","Taxation","Privatisation proceeds"]',2,'Taxation is the primary source of government revenue in most countries.','easy',1),
('Economics',1,'mcq','Money and Banking',2022,'The primary purpose of a central bank is to:','["Provide loans to individuals","Manage the money supply and maintain price stability","Invest in stocks","Issue import licences"]',1,'Central banks (like the Central Bank of Liberia) manage monetary policy, control money supply, and maintain price stability.','easy',1),
('Economics',1,'mcq','International Trade',2021,'A trade deficit occurs when:','["Exports exceed imports","Imports exceed exports","The balance of payments is zero","Exports and imports are equal"]',1,'A trade deficit means a country imports more than it exports — its trade balance is negative.','easy',1),
('Economics',1,'mcq','Basic Concepts',2022,'Economies of scale refer to:','["Cost advantages from increasing scale of production","Cost increases when production rises","Fixed costs only","Benefits from trading internationally"]',0,'Economies of scale: as output increases, average costs fall — firms become more efficient at larger scales.','medium',1),
('Economics',1,'mcq','Demand',2022,'A Giffen good is one where:','["Demand falls as income rises","Demand rises as price rises","Supply falls as price rises","Demand is perfectly inelastic"]',1,'A Giffen good (theoretical) violates normal demand — demand rises as price rises because the income effect outweighs the substitution effect.','hard',1),
('Economics',1,'mcq','Production',2021,'Fixed costs are costs that:','["Change with the level of output","Do not change with the level of output in the short run","Are always zero","Equal variable costs"]',1,'Fixed costs (rent, insurance, machinery) remain constant regardless of output level in the short run.','easy',1),
('Economics',1,'mcq','Market Structures',2022,'Price discrimination is possible only when:','["All consumers have identical incomes","The seller can separate markets with different price elasticities","Competition is perfect","The good is a public good"]',1,'Price discrimination requires market power, ability to separate markets, and prevent resale — each segment has different elasticities.','hard',1),
('Economics',1,'mcq','Inflation',2021,'Demand-pull inflation occurs when:','["Aggregate demand exceeds aggregate supply","Production costs rise sharply","The government prints too little money","Unemployment rises"]',0,'Demand-pull inflation: too much money chasing too few goods — aggregate demand exceeds the economy''s productive capacity.','medium',1),
('Economics',1,'mcq','Development Economics',2022,'Foreign Direct Investment (FDI) refers to:','["Loans from the World Bank","Investment by foreign firms in a country''s businesses/assets","Aid from foreign governments","Remittances from citizens abroad"]',1,'FDI is when foreign companies invest directly in businesses, factories, or assets in another country.','medium',1),
('Economics',1,'mcq','National Income',2022,'If nominal GDP = $500 billion and the GDP deflator = 125, real GDP is:','["$625 billion","$400 billion","$375 billion","$500 billion"]',1,'Real GDP = (Nominal GDP / GDP deflator) × 100 = (500/125) × 100 = $400 billion.','hard',1),
('Economics',1,'mcq','Money and Banking',2020,'Open market operations involve the central bank:','["Setting tax rates","Buying or selling government securities to control money supply","Printing new currency","Regulating foreign exchange rates only"]',1,'Open market operations: buying bonds injects money; selling bonds withdraws money from the economy.','hard',1),
('Economics',1,'mcq','Externalities',2022,'A negative externality occurs when:','["A firm''s production benefits third parties","A firm''s production imposes costs on third parties","Consumers benefit from a product","Government provides a public good"]',1,'Negative externality: production or consumption imposes costs on uninvolved third parties (e.g. pollution).','medium',1),
('Economics',1,'mcq','International Trade',2021,'The purpose of a tariff is to:','["Subsidise domestic producers directly","Tax imports to protect domestic industries","Encourage more imports","Eliminate all trade barriers"]',1,'A tariff is a tax on imported goods, making them more expensive and protecting domestic producers from foreign competition.','easy',1),
('Economics',1,'mcq','Basic Concepts',2022,'The Production Possibility Curve (PPC) illustrates:','["How much firms can produce at zero cost","The trade-off between producing two goods given limited resources","Unlimited production capacity","How prices are determined"]',1,'The PPC shows maximum possible combinations of two goods an economy can produce with given resources — illustrating trade-offs.','medium',1),
('Economics',1,'mcq','Employment',2021,'The natural rate of unemployment includes:','["Cyclical and structural unemployment","Frictional and structural unemployment","Only frictional unemployment","Zero unemployment"]',1,'The natural rate = frictional + structural unemployment. It exists even at "full employment."','hard',1),
('Economics',1,'mcq','Production',2022,'In the long run, all costs are:','["Fixed","Variable","Semi-fixed","Zero"]',1,'In the long run, all factors of production can be changed — all costs become variable.','medium',1),
('Economics',1,'mcq','Development Economics',2021,'Liberia''s Poverty Reduction Strategy is primarily concerned with:','["Attracting tourists","Reducing income inequality and improving public services","Increasing military spending","Limiting foreign trade"]',1,'Liberia''s poverty reduction strategy focuses on reducing poverty through improved governance, services, and economic growth.','medium',1),
('Economics',1,'mcq','Demand',2020,'The substitution effect of a price fall states that:','["Income increases when price falls","The good becomes relatively cheaper so consumers buy more of it","Consumers save more","Firms produce more"]',1,'When a good''s price falls, it becomes cheaper relative to substitutes — consumers substitute toward it (substitution effect).','medium',1),
('Economics',1,'mcq','Market Structures',2022,'Monopsony is a market with:','["One seller","Many buyers and one seller","One buyer","Many sellers and no buyers"]',2,'A monopsony has a single buyer with market power — it can influence the price it pays for inputs/labour.','hard',1),
('Economics',1,'mcq','National Income',2022,'Which of the following is NOT a component of Aggregate Demand?','["Consumption","Investment","Government spending","Imports"]',3,'AD = C + I + G + (X - M). Imports are subtracted, not added — they represent spending on foreign goods.','hard',1),
('Economics',1,'mcq','Money',2021,'Money acts as a unit of account because it:','["Can be easily carried","Provides a standard measure of value for goods and services","Can be stored over time","Is universally accepted"]',1,'Unit of account: money provides a common measure to express and compare the value of goods and services.','medium',1),
('Economics',1,'mcq','Inflation',2022,'Stagflation refers to:','["Rapid economic growth with low inflation","High inflation with stagnant growth and high unemployment","Low inflation and low unemployment","Economic growth with falling prices"]',1,'Stagflation is the simultaneous occurrence of high inflation, stagnant economic growth, and high unemployment — difficult to resolve.','hard',1),
('Economics',1,'mcq','Public Finance',2021,'A budget deficit occurs when:','["Government revenue exceeds expenditure","Government expenditure exceeds revenue","Revenue equals expenditure","Tax rates are reduced"]',1,'A budget deficit: government spends more than it receives in revenue — it must borrow to cover the gap.','easy',1),
('Economics',1,'mcq','International Trade',2022,'Globalisation refers to:','["The spread of a country''s language worldwide","The increasing integration of economies through trade, investment, and technology","Only the spread of multinational corporations","The political unification of countries"]',1,'Globalisation is the process of increasing interconnection of economies, cultures, and governance across borders.','easy',1),
('Economics',1,'mcq','Basic Concepts',2022,'Microeconomics focuses on:','["The economy as a whole","Individual markets, firms, and consumers","National income","International trade policy"]',1,'Microeconomics studies the behaviour of individual economic units: households, firms, and markets.','easy',1);


-- ============================================================
-- GEOGRAPHY — 50 MCQ (Paper 1)
-- ============================================================
INSERT INTO questions (subject, paper_number, question_type, topic, year, question_text, options, correct_answer_index, explanation, difficulty, marks) VALUES

('Geography',1,'mcq','Physical Geography',2022,'The process by which rocks are broken down in their original location without being moved is:','["Erosion","Transportation","Weathering","Deposition"]',2,'Weathering is the breakdown of rock in situ (in place). Erosion involves the removal and transport of material.','easy',1),
('Geography',1,'mcq','Climate',2021,'The ITCZ (Intertropical Convergence Zone) moves northward between:','["December and February","June and August","March and May only","It does not move"]',1,'The ITCZ follows the overhead sun, moving north of the equator approximately June–August and south November–February.','medium',1),
('Geography',1,'mcq','Liberia',2022,'The St. Paul River in Liberia flows into:','["The Gulf of Guinea at Monrovia","Lake Piso","The Niger River","Sierra Leone"]',0,'The St. Paul River empties into the Atlantic Ocean near Monrovia, close to the St. Paul River Bridge.','medium',1),
('Geography',1,'mcq','Map Work',2021,'On a topographic map, the height difference between two consecutive contour lines is called the:','["Scale","Contour interval","Relief","Benchmark"]',1,'The contour interval is the vertical difference in elevation between adjacent contour lines on a map.','easy',1),
('Geography',1,'mcq','Population',2022,'The term "population density" means:','["The total number of people in a country","The number of people per unit area","The rate of population growth","The difference between births and deaths"]',1,'Population density = total population ÷ total area. It measures how crowded an area is.','easy',1),
('Geography',1,'mcq','Economic Geography',2021,'Subsistence farming is characterised by:','["Large-scale production for export","Growing crops mainly for the farmer''s own consumption","Use of heavy machinery","High financial returns"]',1,'Subsistence farmers grow food primarily to feed their own families, with little or nothing left to sell.','easy',1),
('Geography',1,'mcq','Physical Geography',2022,'An oxbow lake is formed when:','["A river floods its valley","A meander is cut off from the main river","A glacier retreats","Underground water emerges"]',1,'As a river meander is bypassed during a flood, the old loop is cut off, forming a crescent-shaped oxbow lake.','medium',1),
('Geography',1,'mcq','Climate',2020,'The main difference between weather and climate is that:','["Weather is warm and climate is cold","Climate is the average weather conditions over a long period","Weather cannot be measured","Climate changes daily"]',1,'Weather is the day-to-day atmospheric conditions. Climate is the average weather pattern over at least 30 years.','easy',1),
('Geography',1,'mcq','Liberia',2022,'Nimba County is known for mining:','["Gold and diamonds","Iron ore","Rubber only","Coal"]',1,'The Nimba Range in Nimba County has one of the world''s largest iron ore deposits, mined by ArcelorMittal.','easy',1),
('Geography',1,'mcq','Map Work',2021,'Grid references on a map are read:','["Up then across (northings first)","Across then up (eastings first, then northings)","Diagonally","From the centre outward"]',1,'Grid references: always read along the bottom axis first (eastings), then up (northings) — "Along the corridor, then up the stairs."','medium',1),
('Geography',1,'mcq','Population',2022,'The demographic transition model shows that in Stage 1:','["Birth rates are low and death rates are low","Birth rates are high and death rates are high","Birth rates are falling","Population grows very rapidly"]',1,'Stage 1 (pre-industrial): both birth and death rates are high and fluctuating — population is small and stable.','medium',1),
('Geography',1,'mcq','Rivers',2021,'A V-shaped valley is formed by:','["Glacial erosion","River erosion in the upper course","Wind erosion","Wave erosion"]',1,'In the upper course, rivers cut downward rapidly through hard rock, forming steep-sided V-shaped valleys.','easy',1),
('Geography',1,'mcq','Economic Geography',2022,'The largest rubber plantation in Liberia is operated by:','["Bridgestone","Michelin","Firestone","Goodyear"]',2,'Firestone operates the Harbel plantation in Margibi County — one of the world''s largest natural rubber plantations.','easy',1),
('Geography',1,'mcq','Physical Geography',2020,'The process by which weathered material is carried from one place to another is:','["Deposition","Erosion","Transportation","Abrasion"]',2,'Transportation is the movement of eroded material by rivers, glaciers, wind, or waves to another location.','easy',1),
('Geography',1,'mcq','Climate',2022,'Liberia receives rainfall predominantly from which wind system?','["Trade winds from the northeast","Southwest monsoon winds from the Atlantic","Harmattan from the Sahara","Polar winds from the south"]',1,'Liberia''s heavy rainfall is brought by moist southwest monsoon winds from the Atlantic Ocean — particularly May to October.','medium',1),
('Geography',1,'mcq','Map Work',2021,'Latitude lines on a map run:','["North to south","East to west (parallel to equator)","Diagonally","Vertically from poles"]',1,'Lines of latitude run east-west, parallel to the equator. The equator is 0°.','easy',1),
('Geography',1,'mcq','Population',2022,'Rural-urban migration in West Africa is mainly caused by:','["Better weather in cities","Higher wages, employment opportunities, and services in cities","Better farming in cities","Government relocation policies"]',1,'People migrate from rural to urban areas seeking better economic opportunities, jobs, healthcare, and education.','easy',1),
('Geography',1,'mcq','Soils',2021,'Laterite soils common in Liberia are:','["Rich in organic matter and fertile","Leached of nutrients due to heavy rainfall, often reddish and iron-rich","Dark and very fertile","Sandy and dry"]',1,'Laterite soils result from intense leaching in tropical climates — nutrients are washed away, leaving iron and aluminium oxides (red colour).','hard',1),
('Geography',1,'mcq','Rivers',2022,'The process by which rivers deposit material when they lose energy is called:','["Erosion","Hydraulic action","Abrasion","Deposition"]',3,'Deposition occurs when a river slows down and loses energy — it drops its load of sediment.','easy',1),
('Geography',1,'mcq','Physical Geography',2021,'Which type of rock is formed from the cooling of magma?','["Sedimentary","Metamorphic","Igneous","Limestone"]',2,'Igneous rock forms from the solidification of magma (underground) or lava (surface) — e.g. granite, basalt.','easy',1),
('Geography',1,'mcq','Economic Geography',2022,'In West Africa, the largest producer of cocoa is:','["Liberia","Nigeria","Côte d''Ivoire (Ivory Coast)","Senegal"]',2,'Côte d''Ivoire is the world''s largest cocoa producer, accounting for around 40% of global production.','medium',1),
('Geography',1,'mcq','Climate',2020,'The Harmattan wind in West Africa blows from:','["The Atlantic Ocean, bringing moisture","The Sahara Desert, bringing dry dusty air","The Gulf of Guinea","The south"]',1,'The Harmattan is a dry, dusty northeast trade wind that blows from the Sahara Desert over West Africa, typically November–March.','medium',1),
('Geography',1,'mcq','Map Work',2022,'The scale 1:50,000 on a map means:','["1 cm on the map = 50,000 cm in reality","1 m on the map = 50,000 m in reality","1 km on the map = 50,000 km in reality","50,000 cm on the map = 1 cm in reality"]',0,'1:50,000 means 1 unit on the map represents 50,000 of the same units in reality. So 1 cm = 50,000 cm = 500 m = 0.5 km.','medium',1),
('Geography',1,'mcq','Population',2021,'A high dependency ratio means:','["Most people are of working age","A large proportion of the population is very young or very old","The population is growing slowly","Most people are employed"]',1,'A high dependency ratio indicates many young and/or elderly people relative to the working-age population.','medium',1),
('Geography',1,'mcq','Rivers',2022,'A delta forms at the mouth of a river when:','["The river flows faster","The river deposits sediment faster than the sea removes it","The river erodes the coastline","Tidal forces are very strong"]',1,'A delta builds up when a river deposits sediment at its mouth faster than waves and currents can carry it away.','medium',1),
('Geography',1,'mcq','Physical Geography',2021,'The epicentre of an earthquake is:','["Deep underground where the earthquake originates","The point on the surface directly above the focus","The measurement of earthquake strength","The wave produced by the earthquake"]',1,'The epicentre is the point on Earth''s surface directly above the focus (hypocentre) where the earthquake originates.','medium',1),
('Geography',1,'mcq','Liberia',2022,'Monrovia, the capital of Liberia, is named after:','["A Liberian founder","U.S. President James Monroe","The Mano River","A British explorer"]',1,'Monrovia was named after James Monroe, the 5th U.S. President, who supported the establishment of Liberia.','easy',1),
('Geography',1,'mcq','Economic Geography',2021,'Plantation farming in Liberia is primarily associated with:','["Food crops for local consumption","Cash crops (rubber, oil palm) for export","Subsistence rice farming","Urban market gardening"]',1,'Liberia''s plantation sector produces commercial (cash) crops — mainly rubber and oil palm — primarily for export.','easy',1),
('Geography',1,'mcq','Climate',2022,'The annual rainfall in Monrovia, Liberia is approximately:','["500 mm","1000 mm","4500 mm","200 mm"]',2,'Monrovia is one of the wettest capitals in the world, receiving approximately 4,500 mm of rain per year.','medium',1),
('Geography',1,'mcq','Map Work',2020,'Contour lines that are close together on a map indicate:','["Flat terrain","Gently sloping land","Steep slopes","Water bodies"]',2,'Closely spaced contour lines indicate a rapid change in elevation over a short horizontal distance — steep terrain.','easy',1),
('Geography',1,'mcq','Population',2022,'Zero population growth occurs when:','["Birth rate equals death rate","Only births exceed deaths","Immigration exceeds emigration","Population is very large"]',0,'Zero population growth: birth rate = death rate (and immigration = emigration) — total population is stable.','medium',1),
('Geography',1,'mcq','Coasts',2021,'Wave-cut platforms are formed by:','["River deposition","Glacial action","Marine erosion at the base of cliffs","Wind erosion"]',2,'Wave-cut platforms are flat rocky surfaces at the foot of cliffs, formed as waves erode the cliff base.','medium',1),
('Geography',1,'mcq','Physical Geography',2022,'Metamorphic rocks are formed by:','["Cooling of lava","Deposition of sediments","Heat and pressure acting on existing rocks","Volcanic eruptions only"]',2,'Metamorphic rocks form when existing rocks are changed by heat and/or pressure (e.g. marble from limestone).','medium',1),
('Geography',1,'mcq','Economic Geography',2020,'Logging (timber extraction) in Liberia has been controversial mainly because of:','["Low timber prices","Deforestation and loss of biodiversity","High labour costs","Lack of equipment"]',1,'Unsustainable logging in Liberia''s forests has led to significant deforestation and threats to biodiversity.','medium',1),
('Geography',1,'mcq','Climate',2021,'The dry season in Liberia generally occurs between:','["May and October","November and April","July and August","All year round"]',1,'Liberia''s dry season (influenced by the Harmattan) generally runs from November to April.','easy',1),
('Geography',1,'mcq','Population',2022,'The most populous country in West Africa is:','["Ghana","Liberia","Côte d''Ivoire","Nigeria"]',3,'Nigeria, with over 220 million people, is the most populous country in West Africa and in Africa.','easy',1),
('Geography',1,'mcq','Rivers',2021,'In the lower course of a river, which features are most common?','["Waterfalls and gorges","Meanders, flood plains, and oxbow lakes","V-shaped valleys","Rapids"]',1,'In the lower course, the river has lost energy and moves across flat plains, forming meanders, flood plains, and depositing alluvium.','easy',1),
('Geography',1,'mcq','Physical Geography',2022,'The Richter Scale measures:','["Depth of an earthquake","Intensity of earthquake shaking","Magnitude (energy released) of an earthquake","Speed of seismic waves"]',2,'The Richter Scale measures the magnitude (energy released) of an earthquake. Each whole number = 10× more ground motion.','medium',1),
('Geography',1,'mcq','Liberia',2021,'The Mano River forms part of Liberia''s border with:','["Guinea","Côte d''Ivoire","Sierra Leone","Ghana"]',2,'The Mano River forms the northern section of the border between Liberia and Sierra Leone.','medium',1),
('Geography',1,'mcq','Map Work',2022,'A bearing of 090° on a compass indicates which direction?','["North","East","South","West"]',1,'Compass bearings: 000°/360° = North, 090° = East, 180° = South, 270° = West.','easy',1),
('Geography',1,'mcq','Economic Geography',2022,'Which of these best describes Liberia''s economy?','["Highly industrialised","Natural resource-dependent with emerging agriculture","Service-based with high technology sector","Primarily based on manufacturing"]',1,'Liberia''s economy remains heavily dependent on natural resources (rubber, iron ore, gold, timber) with significant subsistence agriculture.','medium',1),
('Geography',1,'mcq','Climate',2020,'Deforestation contributes to climate change mainly by:','["Increasing rainfall","Releasing stored carbon into the atmosphere","Reducing wind speed","Cooling the atmosphere"]',1,'Trees store carbon. When forests are cleared and burned, stored carbon is released as CO₂, contributing to the greenhouse effect.','medium',1),
('Geography',1,'mcq','Population',2021,'Overpopulation occurs when:','["A country has too few people","The population exceeds the carrying capacity of the environment","Birth rate is equal to death rate","All people live in urban areas"]',1,'Overpopulation: population exceeds the resources and environmental capacity available to sustain it.','medium',1),
('Geography',1,'mcq','Coasts',2022,'A tombolo is:','["A stack formed by wave erosion","A sand or gravel bar connecting an island to the mainland","A type of sand dune","An underwater ridge"]',1,'A tombolo is a depositional landform — a spit of sand or gravel that connects an island to the mainland or another island.','hard',1),
('Geography',1,'mcq','Physical Geography',2021,'The term "relief" in geography refers to:','["Weather conditions","The variation in elevation of the land surface","Soil quality","Vegetation cover"]',1,'Relief describes the differences in elevation across a landscape — its hills, valleys, and plains.','easy',1),
('Geography',1,'mcq','West Africa',2022,'The Sahel region of West Africa is characterised by:','["Tropical rainforest","Semi-arid conditions with unreliable rainfall at the desert margin","Coastal mangroves","Dense tropical forest"]',1,'The Sahel is a semi-arid transitional belt between the Sahara Desert to the north and savanna to the south.','medium',1),
('Geography',1,'mcq','Liberia',2022,'The major ethnic groups of Liberia include all of the following EXCEPT:','["Kpelle","Bassa","Grebo","Hausa"]',3,'The Hausa people are primarily from northern Nigeria/Niger. The Kpelle, Bassa, and Grebo are among Liberia''s indigenous ethnic groups.','medium',1),
('Geography',1,'mcq','Rivers',2020,'Hydraulic action is:','["Chemical weathering by river water","The force of moving water breaking apart rock","The wearing away of rock by sediment","Deposition of material in the river bed"]',1,'Hydraulic action is the physical force of fast-moving water being forced into cracks in rocks, eventually causing them to break apart.','medium',1),
('Geography',1,'mcq','Map Work',2021,'A cross-section on a topographic map shows:','["The aerial view of the land","A side-view profile of the landscape along a given line","The distribution of vegetation","Population density"]',1,'A cross-section is a vertical slice through the landscape along a given line, showing the shape of relief.','medium',1),
('Geography',1,'mcq','Physical Geography',2022,'Convectional rainfall in the tropics occurs when:','["Cold air meets warm air at a front","The land heats up, causing warm moist air to rise rapidly and cool","Onshore winds bring moist air over mountains","Wind forces moist air over high ground"]',1,'Convectional rainfall: solar heating causes rapid evaporation and rising air, which cools and condenses at altitude — common near the equator.','medium',1);

-- ============================================================
-- LITERATURE IN ENGLISH — 50 MCQ (Paper 1)
-- ============================================================
INSERT INTO questions (subject, paper_number, question_type, topic, year, question_text, options, correct_answer_index, explanation, difficulty, marks) VALUES

('Literature in English',1,'mcq','Literary Terms',2022,'A narrative poem that tells a story, often of adventure or romance, is called a:','["Sonnet","Ballad","Elegy","Ode"]',1,'A ballad is a narrative poem that tells a story, often set to music, dealing with adventure, love, or tragedy.','easy',1),
('Literature in English',1,'mcq','Drama',2021,'A soliloquy is:','["A conversation between two characters","A speech by a single character alone on stage revealing inner thoughts","A summary by the narrator","A group recitation by the chorus"]',1,'A soliloquy is a dramatic device where a character speaks their private thoughts aloud, alone on stage.','easy',1),
('Literature in English',1,'mcq','Literary Devices',2022,'Onomatopoeia is:','["Giving human traits to non-human things","Words that imitate sounds (e.g. buzz, crash)","A comparison using like or as","Exaggeration for effect"]',1,'Onomatopoeia is when a word phonetically imitates the sound it describes — e.g. "hiss," "buzz," "crash."','easy',1),
('Literature in English',1,'mcq','African Literature',2021,'"Things Fall Apart" by Chinua Achebe deals primarily with:','["The Nigerian civil war","The collision between Igbo culture and British colonialism","A love story in Lagos","The Biafran conflict"]',1,'"Things Fall Apart" depicts the life of Okonkwo and the disruption of Igbo society by British colonialism and Christian missionaries.','easy',1),
('Literature in English',1,'mcq','Poetry',2022,'A couplet is:','["A group of four lines","Two consecutive lines of poetry that rhyme","A single long line","A stanza with no rhyme"]',1,'A couplet consists of two consecutive lines of poetry, typically with a rhyme scheme (AA).','easy',1),
('Literature in English',1,'mcq','Literary Devices',2021,'The literary term for giving human characteristics to abstract ideas or non-human things is:','["Metaphor","Simile","Personification","Synecdoche"]',2,'Personification attributes human qualities to inanimate objects or abstract concepts: "The wind whispered."','easy',1),
('Literature in English',1,'mcq','Drama',2022,'In drama, the central conflict of the story is resolved during the:','["Exposition","Rising action","Climax","Denouement"]',3,'The denouement is the final part of a play where loose ends are resolved after the climax.','medium',1),
('Literature in English',1,'mcq','Poetry',2021,'A poem of fourteen lines usually written in iambic pentameter is a:','["Ballad","Ode","Haiku","Sonnet"]',3,'A sonnet is a 14-line poem, typically written in iambic pentameter, with a specific rhyme scheme.','easy',1),
('Literature in English',1,'mcq','Prose',2022,'An omniscient narrator is one who:','["Knows only their own thoughts","Knows the thoughts and feelings of all characters","Is a character in the story","Tells the story in second person"]',1,'An omniscient (all-knowing) narrator has complete knowledge of all characters'' thoughts, feelings, and events.','medium',1),
('Literature in English',1,'mcq','Literary Devices',2020,'Irony in literature refers to:','["Direct statements of fact","A difference between appearance/expectation and reality","Repetition of words","Sound patterns in poetry"]',1,'Irony involves a contrast between what is said/expected and what actually happens or is meant.','medium',1),
('Literature in English',1,'mcq','African Literature',2022,'The author of "Weep Not, Child" is:','["Chinua Achebe","Ngugi wa Thiong''o","Wole Soyinka","Chimamanda Adichie"]',1,'"Weep Not, Child" (1964) was written by Ngugi wa Thiong''o of Kenya — the first novel in English by an East African author.','medium',1),
('Literature in English',1,'mcq','Drama',2021,'A dramatic technique where the audience knows something the characters do not is called:','["Dramatic irony","Foreshadowing","Soliloquy","Aside"]',0,'Dramatic irony creates tension by letting the audience know crucial information that characters on stage are unaware of.','medium',1),
('Literature in English',1,'mcq','Literary Devices',2022,'A metaphor is:','["A comparison using like or as","A direct comparison stating one thing IS another","Repetition of consonants","A humorous comparison"]',1,'A metaphor makes a direct comparison without using "like" or "as" — it states that one thing is another: "Life is a journey."','easy',1),
('Literature in English',1,'mcq','Poetry',2020,'The metre "da-DUM da-DUM da-DUM da-DUM da-DUM" (10 syllables) is:','["Trochaic tetrameter","Iambic pentameter","Dactylic hexameter","Anapestic trimeter"]',1,'Iambic pentameter: 5 iambs (da-DUM) = 10 syllables per line. Used extensively by Shakespeare.','medium',1),
('Literature in English',1,'mcq','Prose',2021,'Stream of consciousness is a narrative technique that:','["Describes events in strictly chronological order","Mimics the continuous flow of a character''s thoughts","Uses only dialogue","Is told from multiple viewpoints simultaneously"]',1,'Stream of consciousness attempts to replicate the natural, often fragmented flow of a character''s inner thoughts.','hard',1),
('Literature in English',1,'mcq','Literary Terms',2022,'The "setting" of a literary work refers to:','["The main character","The central conflict","The time and place where events occur","The moral lesson"]',2,'Setting is the time (historical period, time of day) and place (location, environment) in which a story is set.','easy',1),
('Literature in English',1,'mcq','Drama',2022,'An aside in drama is when:','["A character leaves the stage","A character speaks directly to the audience, unheard by other characters","Two characters have a private conversation","The chorus summarises the action"]',1,'An aside is a remark made by a character directly to the audience, not heard by other characters on stage.','medium',1),
('Literature in English',1,'mcq','Literary Devices',2021,'Hyperbole is:','["Understatement for effect","Exaggeration used for emphasis or humour","The use of symbols","A reference to another text"]',1,'Hyperbole is extreme exaggeration: "I''ve told you a million times."','easy',1),
('Literature in English',1,'mcq','African Literature',2022,'The playwright who wrote "Death and the King''s Horseman" is:','["Chinua Achebe","Ngugi wa Thiong''o","Wole Soyinka","Ama Ata Aidoo"]',2,'Wole Soyinka (Nigerian Nobel Laureate) wrote "Death and the King''s Horseman" (1975), exploring Yoruba ritual and colonial disruption.','medium',1),
('Literature in English',1,'mcq','Poetry',2022,'Free verse poetry:','["Follows strict metre and rhyme","Has no regular metre or rhyme scheme","Always has exactly 14 lines","Uses only couplets"]',1,'Free verse is poetry without a fixed metre, rhyme scheme, or line length — it follows the natural rhythms of speech.','easy',1),
('Literature in English',1,'mcq','Prose',2020,'Flashback in a narrative is:','["An event described in the future tense","An interruption in the narrative to describe a past event","A scene set in a different location","A recurring motif"]',1,'A flashback is a narrative technique that takes the story back in time to reveal past events relevant to the present action.','easy',1),
('Literature in English',1,'mcq','Literary Terms',2021,'The protagonist of a story is:','["Always the narrator","The main character around whom the plot revolves","Always the hero","The villain"]',1,'The protagonist is the central character of the story — they drive the plot and face the main conflict.','easy',1),
('Literature in English',1,'mcq','Drama',2022,'The three classical unities (Aristotle) are:','["Time, place, and action","Character, plot, and setting","Exposition, climax, and resolution","Comedy, tragedy, and history"]',0,'The three Aristotelian unities: unity of time (action within one day), place (one location), and action (one main plot).','hard',1),
('Literature in English',1,'mcq','Literary Devices',2021,'An allusion is:','["A brief reference to a well-known person, place, event, or text","A comparison using like or as","Repetition of vowel sounds","A contradiction that reveals a truth"]',0,'An allusion is an indirect reference to another work, historical event, or well-known figure.','medium',1),
('Literature in English',1,'mcq','Poetry',2022,'The refrain in a poem is:','["The first stanza","A line or lines repeated at intervals throughout the poem","The last line only","A change in metre"]',1,'A refrain is a line or group of lines repeated at regular intervals in a poem, often at the end of each stanza.','easy',1),
('Literature in English',1,'mcq','Prose',2021,'A round character in fiction is one who:','["Is described in great detail physically","Is simple, one-dimensional","Is complex and undergoes development","Always survives to the end"]',2,'Round characters are complex, multi-dimensional, and may change or grow throughout the story.','medium',1),
('Literature in English',1,'mcq','Literary Terms',2022,'The tone of a piece of writing refers to:','["The setting of the story","The author''s attitude toward the subject","The speed of the narrative","The number of characters"]',1,'Tone is the author''s attitude or feeling toward the subject matter, conveyed through word choice and style.','medium',1),
('Literature in English',1,'mcq','Literary Devices',2022,'Symbolism in literature involves:','["The use of actual objects only","Objects, characters, or events representing deeper meanings or ideas","Repeated sounds for musical effect","Events happening in reverse order"]',1,'Symbolism uses an object, person, place, or event to represent something beyond its literal meaning.','medium',1),
('Literature in English',1,'mcq','Poetry',2020,'An elegy is a poem that:','["Celebrates a great hero","Mourns the death of someone or laments something lost","Praises a concept or ideal","Tells an exciting story"]',1,'An elegy is a mournful poem written to lament someone who has died or to express grief and loss.','easy',1),
('Literature in English',1,'mcq','African Literature',2022,'"So Long a Letter" was written by:','["Buchi Emecheta","Aminata Sow Fall","Mariama Bâ","Flora Nwapa"]',2,'"So Long a Letter" (1979) is an epistolary novel by Senegalese author Mariama Bâ, addressing women''s roles and polygamy.','hard',1),
('Literature in English',1,'mcq','Drama',2021,'Catharsis, as described by Aristotle, refers to:','["The build-up of tension in a tragedy","The purging of emotions (pity and fear) in the audience","The tragic flaw of the hero","The resolution of the play"]',1,'Aristotle''s catharsis: watching tragedy allows the audience to release pity and fear, producing emotional relief.','hard',1),
('Literature in English',1,'mcq','Literary Devices',2022,'Assonance is:','["The repetition of consonant sounds at the beginning of words","The repetition of vowel sounds in nearby words","The use of words that imitate sounds","The repetition of entire lines"]',1,'Assonance is the repetition of vowel sounds in nearby words: "The rain in Spain stays mainly in the plain."','medium',1),
('Literature in English',1,'mcq','Prose',2022,'The rising action of a plot is:','["The introduction of characters and setting","Events that build tension toward the climax","The point of highest tension","Events after the climax leading to resolution"]',1,'Rising action is the series of events and complications that build tension and lead toward the story''s climax.','easy',1),
('Literature in English',1,'mcq','Literary Terms',2021,'A foil character is one who:','["Is the main character","Contrasts with another character to highlight their qualities","Is always the antagonist","Has no role in the plot"]',1,'A foil is a character whose contrasting traits highlight or emphasise the qualities of another character (usually the protagonist).','hard',1),
('Literature in English',1,'mcq','Poetry',2022,'The volta in a sonnet is:','["The rhyme scheme","A shift in argument, mood, or perspective","The final couplet only","The opening line"]',1,'The volta is the "turn" in a sonnet — a shift in argument, tone, or perspective, typically at line 9 (Petrarchan) or line 13 (Shakespearean).','hard',1),
('Literature in English',1,'mcq','Literary Devices',2020,'Paradox is:','["A straightforward statement of truth","A statement that seems contradictory but reveals a deeper truth","A humorous comparison","Extreme exaggeration"]',1,'A paradox is a seemingly contradictory statement that, on reflection, contains a truth: "I must be cruel to be kind."','hard',1),
('Literature in English',1,'mcq','Drama',2022,'The antagonist in a play is:','["The main character","The force or character opposing the protagonist","The narrator","The character who dies"]',1,'The antagonist is the character or force that opposes and creates conflict for the protagonist.','easy',1),
('Literature in English',1,'mcq','Prose',2021,'The point of view where the narrator refers to themselves as "I" is:','["Second person","Third person limited","First person","Third person omniscient"]',2,'First-person narration: the narrator is a character in the story and uses "I" — giving a personal, subjective perspective.','easy',1),
('Literature in English',1,'mcq','African Literature',2022,'"Purple Hibiscus" is a novel by:','["Buchi Emecheta","Chinua Achebe","Chimamanda Ngozi Adichie","Ama Ata Aidoo"]',2,'"Purple Hibiscus" (2003) is the debut novel of Chimamanda Ngozi Adichie, set in post-colonial Nigeria.','medium',1),
('Literature in English',1,'mcq','Literary Terms',2021,'The theme of a literary work is:','["The main character''s name","The central idea or message explored throughout the work","The location of the story","The type of narration used"]',1,'Theme is the underlying message, moral question, or central idea the author explores — not merely the subject.','easy',1),
('Literature in English',1,'mcq','Poetry',2022,'Blank verse is:','["Poetry with no words","Unrhymed poetry written in iambic pentameter","Free verse with a refrain","Poetry with only two lines"]',1,'Blank verse is unrhymed iambic pentameter — it has regular metre but no rhyme scheme. Used by Shakespeare in his plays.','hard',1),
('Literature in English',1,'mcq','Literary Devices',2021,'An epigraph is:','["The final chapter of a novel","A short quotation at the beginning of a work setting its tone or theme","The dedication of the book","A footnote"]',1,'An epigraph is a quotation placed at the beginning of a literary work (or chapter) that hints at its themes.','hard',1),
('Literature in English',1,'mcq','Prose',2022,'An unreliable narrator is one who:','["Always tells the exact truth","May distort, misinterpret, or lie about events — the reader must question their account","Only narrates factual events","Has no personality"]',1,'An unreliable narrator''s account cannot be fully trusted — due to mental state, bias, limited knowledge, or deliberate deception.','hard',1),
('Literature in English',1,'mcq','Drama',2020,'A tragic hero, according to Aristotle, must have:','["Great wealth and power only","A fatal flaw (hamartia) that contributes to their downfall","No redeeming qualities","A happy ending"]',1,'Aristotle''s tragic hero has a hamartia (fatal flaw) that leads to their downfall — they are noble but imperfect.','hard',1),
('Literature in English',1,'mcq','Literary Terms',2022,'Mood in a literary work refers to:','["The author''s attitude","The atmosphere or emotional feeling created for the reader","The speed of narration","The setting''s weather"]',1,'Mood is the atmosphere or emotional response the author creates in the reader through setting, language, and imagery.','medium',1),
('Literature in English',1,'mcq','Poetry',2021,'A limerick is a poem with which rhyme scheme?','["AABB","ABAB","AABBA","ABCABC"]',2,'A limerick has 5 lines with rhyme scheme AABBA — lines 1, 2, 5 rhyme; lines 3, 4 rhyme and are shorter.','medium',1),
('Literature in English',1,'mcq','Literary Devices',2022,'Synecdoche is a figure of speech in which:','["The whole stands for the part","A part stands for the whole (or vice versa)","Two unlike things are compared","A sound represents an idea"]',1,'Synecdoche: a part represents the whole (or whole represents part). "All hands on deck" — hands = sailors.','hard',1),
('Literature in English',1,'mcq','African Literature',2021,'The griot in West African oral tradition is:','["A type of drum","A hereditary storyteller, historian, and praise singer","A sacred mask","A traditional healer"]',1,'Griots are hereditary oral historians, storytellers, praise singers, and musicians in West African societies — custodians of tradition.','medium',1),
('Literature in English',1,'mcq','Prose',2022,'Epistolary fiction is:','["A story told through footnotes","A story told through letters, diaries, or documents","A story with no characters","A story set in ancient times"]',1,'Epistolary fiction is told through documents — letters, diary entries, emails — e.g. "So Long a Letter" by Mariama Bâ.','medium',1),
('Literature in English',1,'mcq','Drama',2022,'The deus ex machina is:','["The tragic flaw","An unlikely or contrived resolution introduced at the last moment","A type of villain","The opening scene"]',1,'"Deus ex machina" (god from the machine): an unexpected power or event that suddenly solves a seemingly impossible problem.','hard',1);


